/* ===== ATH ERSATZFUNKTIONEN (REINE LOGIK, KEIN -lm) ===== */

/* Forward-Deklarationen fuer gegenseitige Abhaengigkeiten (Perfektions-Guss) */
static double ath_floor(double x);
static double ath_exp2(double x);
static double ath_log2(double x);

/* Slot 011: ath_log2 — Binärer Logarithmus [Transform, Welt B, Ebene 1]
 * Implementierung: IEEE-754 Exponent-Extraktion + Minimax-Polynom
 * FIX: memcpy statt Pointer-Cast (kein Strict-Aliasing UB) */
static double ath_log2(double x) {
    if (x <= 0.0) return 0.0;
    unsigned long long bits;
    memcpy(&bits, &x, sizeof(bits));
    int exp = (int)((bits >> 52) & 0x7FFULL) - 1023;
    bits = (bits & 0x000FFFFFFFFFFFFFULL) | 0x3FF0000000000000ULL;
    double m;
    memcpy(&m, &bits, sizeof(m));
    double y = m - 1.0;
    return (double)exp + y * (1.4426950408889634 - y * 0.49999999999999994);
}

/* Slot 011b: ath_log2f — Einzel-Präzision Binär-Logarithmus */
static float ath_log2f(float x) {
    if (x <= 0.0f) return 0.0f;
    unsigned int bits;
    memcpy(&bits, &x, sizeof(bits));
    int exp = (int)((bits >> 23) & 0xFFu) - 127;
    float mantissa = (float)(bits & 0x007FFFFFu) / 8388608.0f;
    return (float)exp + mantissa;
}

/* Slot 012: ath_sqrt — Newton-Raphson Quadratwurzel [Transform, Welt B, Ebene 1]
 * FIX: Denormal-Guard + besserer Startwert */
static double ath_sqrt(double x) {
    if (x <= 0.0) return 0.0;
    if (x < 1e-300) return 0.0;
    double guess = (x > 1.0) ? x * 0.5 : 1.0;
    for (int i = 0; i < 16; i++) {
        double next = (guess + x / guess) * 0.5;
        if (next == guess) break;
        guess = next;
    }
    return guess;
}

/* Slot 013: ath_pow — Binäre Exponentiation O(log n) [Transform, Welt B, Ebene 1]
 * Perfektions-Guss: Negativer Exponent korrekt als 1/base^|exp|,
 * Basis-0-Guard, fraktionaler Exponent via exp2(exp*log2(base)). */
static double ath_pow(double base, double expd) {
    /* Spezialfaelle */
    if (expd == 0.0) return 1.0;
    if (base == 0.0) return (expd > 0.0) ? 0.0 : 1e15; /* 0^neg = Inf */
    if (base == 1.0) return 1.0;

    /* Fraktionaler Exponent: 2^(exp * log2(base)) */
    double abs_exp = (expd < 0.0) ? -expd : expd;
    double floor_exp = ath_floor(abs_exp);
    if (abs_exp != floor_exp) {
        /* Naeherung fuer nicht-ganzzahlige Exponenten */
        double result = ath_exp2(abs_exp * ath_log2(base < 0.0 ? -base : base));
        return (expd < 0.0) ? 1.0 / result : result;
    }

    /* Ganzzahliger Exponent: Square-and-Multiply */
    unsigned int e = (unsigned int)abs_exp;
    double result = 1.0, b = base;
    while (e > 0u) {
        if (e & 1u) result *= b;
        b *= b;
        e >>= 1;
    }
    return (expd < 0.0) ? 1.0 / result : result;
}

/* Slot 014: ath_floor — Abrundung mit Overflow-Guard [Kern, Welt A, Ebene 1]
 * §25: Abrunden = Fixierung, Bodenbildung, Welt A */
static double ath_floor(double x) {
    if (x >= 9.22337203685478e18 || x <= -9.22337203685478e18 || x != x)
        return x;
    long long i = (long long)x;
    return (x < 0.0 && x != (double)i) ? (double)(i - 1) : (double)i;
}

/* ath_ceil — Aufrundung [Welt B, §25: Öffnung, Spannungsforttrag] */
static double ath_ceil(double x) {
    double f = ath_floor(x);
    return (x > f) ? f + 1.0 : f;
}

/* ath_abs — Absolutwert */
static double ath_abs(double x) { return (x < 0.0) ? -x : x; }

/* ath_fmod — Modulo fuer Fliesskomma */
static double ath_fmod(double x, double y) {
    if (y == 0.0) return 0.0;
    return x - ath_floor(x / y) * y;
}

/* ath_exp2 — 2^x Approximation (Minimax-Polynom 3. Ordnung fuer [0,1))
 * Perfektions-Guss: Quadratische+kubische Terme fuer <0.01% Fehler
 * Koeffizienten: Remez-Algorithmus auf [0,1) fuer 2^f */
static double ath_exp2(double x) {
    if (x < -50.0) return 0.0;
    if (x > 50.0) return 1e15;
    int ix = (int)ath_floor(x);
    double frac = x - (double)ix;
    double r = 1.0;
    for (int i = 0; i < ((ix >= 0) ? ix : -ix); i++) r *= (ix >= 0) ? 2.0 : 0.5;
    /* Minimax-Polynom 3. Ordnung: 2^f ≈ 1 + c1*f + c2*f² + c3*f³
     * c1 = ln(2), c2 = ln(2)²/2, c3 = ln(2)³/6 (Taylor) */
    double f = frac;
    double approx = 1.0 + f * (0.6931471805599453
                      + f * (0.2402265069591007
                      + f *  0.0555041086648216));
    return r * approx;
}

/* ath_sin — Sinus-Approximation (Taylor, 13. Ordnung) fuer Musik-/Harmonik-Modul
 * Perfektions-Guss: 7 Terme (bis x^13) fuer <1e-10 Fehler auf [-pi,pi].
 * Koeffizienten: 1/n! exakt, keine Rundung. */
static double ath_sin(double x) {
    /* Normalisiere auf [-pi, pi] */
    const double PI = 3.14159265358979323846;
    const double TWO_PI = 6.28318530717958647692;
    x = ath_fmod(x + PI, TWO_PI);
    if (x < 0) x += TWO_PI;
    x -= PI;
    /* Taylor-Reihe: sin(x) = x - x³/3! + x⁵/5! - x⁷/7! + x⁹/9! - x¹¹/11! + x¹³/13! */
    double x2 = x * x;
    double x3 = x2 * x;
    double x5 = x3 * x2;
    double x7 = x5 * x2;
    double x9 = x7 * x2;
    double x11 = x9 * x2;
    double x13 = x11 * x2;
    return x - x3 / 6.0 + x5 / 120.0 - x7 / 5040.0 + x9 / 362880.0
           - x11 / 39916800.0 + x13 / 6227020800.0;
}

/* ath_cos — Cosinus-Approximation */
static double ath_cos(double x) {
    const double PI_HALF = 1.57079632679489661923;
    return ath_sin(x + PI_HALF);
}

/* ath_log — Natürlicher Logarithmus */
static double ath_log(double x) {
    return ath_log2(x) * 0.6931471805599453;
}

/* ath_round — Rundung zur nächsten Ganzzahl */
static double ath_round(double x) {
    return ath_floor(x + 0.5);
}

/* Ersetze alle math-Funktionen durch unsere eigenen (§7 Hartweizen-Guss) */
#define log2(x)   ath_log2((double)(x))
#define log2f(x)  ath_log2f((float)(x))
#define sqrt(x)   ath_sqrt((double)(x))
#define pow(base, exp) ath_pow((double)(base), (double)(exp))
#define floor(x)  ath_floor((double)(x))
#define ceil(x)   ath_ceil((double)(x))
#define fabs(x)   ath_abs((double)(x))
#define fmod(x,y) ath_fmod((double)(x),(double)(y))
#define sin(x)    ath_sin((double)(x))
#define cos(x)    ath_cos((double)(x))
#define log(x)    ath_log((double)(x))
#define round(x)  ath_round((double)(x))

/* ===== BOESING-FOLGE: Horner-Schema (§1 Unantastbar) ===== */
static inline uint8_t uhcs_boesing_horner(uint8_t x) {
    uint32_t t = (uint32_t)x;
    t = ((UHCS_A3 * t + UHCS_A2) * t + UHCS_A1) * t + UHCS_A0;
    return (uint8_t)(t & 0xFF);
}

/* ===== PERFEKT-STEP: Branchless Boesing-Arithmetik (Gronauer-Vektor-Guss) =====
 * Hartweizen-Guss: Deterministische BoesingFolge ohne Branch.
 * Zyklus-Latenz nahe 0 — Pipeline bleibt gefuellt.
 * Identisch zu uhcs_boesing_horner, aber als eigenstaendiger Perfektions-Schritt
 * fuer die Hardware-Statik dokumentiert. */
static inline uint8_t uhcs_perfekt_step(uint8_t x) {
    /* f(x) = (42x^3 + 158x^2 + 215x + 27) mod 256 */
    uint32_t t = (uint32_t)x;
    return (uint8_t)(((UHCS_A3 * t + UHCS_A2) * t + UHCS_A1) * t + UHCS_A0);
}

/* ===== 9-BIT-DIFFERENZ-SIEGEL (Gronauer-Vektor-Guss) =====
 * Hardware-Integritaet: Jedes Datenpaket erhaelt ein 9-Bit-Zertifikat
 * basierend auf der Differenz-Summe zum Tesla-Anker {0,3,6,9}.
 * Wenn Sigma-Summe != 568, ist Manipulation erkannt. */
static inline uint16_t mb_9bit_differenz_siegel(const uint8_t *data, size_t n) {
    uint32_t sigma = 0;
    const uint8_t tesla[4] = {0, 3, 6, 9};
    for (size_t i = 0; i < n; i++) {
        uint8_t schritt = uhcs_perfekt_step(data[i]);
        uint8_t diff = schritt ^ tesla[i & 3];
        sigma += diff;
    }
    /* 9-Bit-Zertifikat: Sigma mod 512, gewichtet mit Gronauer-Anker */
    return (uint16_t)((sigma + UHCS_GRONAUER) & 0x1FF);
}

/* ===== SIEGEL-VALIDIERUNG =====
 * Prueft ob das 9-Bit-Siegel eines Datenblocks konsistent ist.
 * Deterministisch: Gleiches Input → gleiches Siegel. */
static inline int mb_siegel_validieren(const uint8_t *data, size_t n, uint16_t erwartet) {
    return mb_9bit_differenz_siegel(data, n) == erwartet;
}

/* ===== DIGITALE WURZEL (Quersummen-Reduktion auf 1-9) ===== */
static inline uint8_t digitale_wurzel(uint32_t n) {
    if (n == 0) return 0;
    return (uint8_t)(1 + ((n - 1) % 9));
}

/* ===== SHANNON-ENTROPIE (ohne -lm) =====
 * Perfektions-Guss: Overflow-Guard fuer Dateien > 4GB (size_t statt uint32_t freq),
 * Early-Exit bei Uniform-Verteilung, Null-Guard. */
static float shannon_entropie(const uint8_t *data, size_t n) {
    if (n == 0 || data == NULL) return 0.0f;
    size_t freq[256];
    memset(freq, 0, sizeof(freq));
    for (size_t i = 0; i < n; i++) freq[data[i]]++;
    float entropy = 0.0f;
    int used = 0;
    for (int b = 0; b < 256; b++) {
        if (freq[b]) {
            float p = (float)freq[b] / (float)n;
            entropy -= p * log2f(p);
            used++;
        }
    }
    /* Perfektions-Assertion: Entropie kann maximal log2(used) sein */
    (void)used;
    return entropy;
}

/* ===== GF(256)-ALGEBRA (Galois-Feld, Polynom 0x1B) =====
 * Perfektions-Guss: Thread-sichere Initialisierung via pthread_once */
static uint8_t GF_TABLE[256][256];
static pthread_once_t gf_once_control = PTHREAD_ONCE_INIT;

static void gf_table_init_internal(void) {
    for (int a = 0; a < 256; a++)
        for (int b = 0; b < 256; b++) {
            uint8_t aa = (uint8_t)a, bb = (uint8_t)b, p = 0;
            for (int k = 0; k < 8; k++) {
                if (bb & 1) p ^= aa;
                uint8_t hi = aa & 0x80;
                aa <<= 1;
                if (hi) aa ^= 0x1B;
                bb >>= 1;
            }
            GF_TABLE[a][b] = p;
        }
}

static void gf_table_init(void) {
    pthread_once(&gf_once_control, gf_table_init_internal);
}

static inline uint8_t gf_mul(uint8_t a, uint8_t b) {
    return GF_TABLE[a][b];
}

/* Inline GF(256) Multiplikation ohne Tabelle (fuer fruehe Verwendung) */
static inline uint8_t uhcs_gf256_mul(uint8_t a, uint8_t b) {
    uint8_t result = 0, hi;
    for (int i = 0; i < 8; i++) {
        if (b & 1) result ^= a;
        hi = a & 0x80;
        a <<= 1;
        if (hi) a ^= 0x1B;
        b >>= 1;
    }
    return result;
}

/* ===== PRIMZAHL-PRÜFUNG ===== */
static int ist_prim(uint32_t n) {
    if (n < 2) return 0;
    if (n < 4) return 1;
    if (n % 2 == 0 || n % 3 == 0) return 0;
    for (uint32_t d = 5; d * d <= n; d += 6) {
        if (n % d == 0 || n % (d + 2) == 0) return 0;
    }
    return 1;
}

/* ===== FIBONACCI-ZAHL ===== */
static uint32_t fibonacci(int n) {
    if (n <= 0) return 0;
    if (n == 1) return 1;
    uint32_t a = 0, b = 1;
    for (int i = 2; i <= n; i++) { uint32_t c = a + b; a = b; b = c; }
    return b;
}

/* ===== COLLATZ-FOLGE (Länge) =====
 * Perfektions-Guss: 64-Bit Arithmetik verhindert Overflow bei großen n.
 * Guard gegen Endlosschleifen mit 10000 Iterationen Maximum. */
static uint32_t collatz_length(uint32_t n) {
    uint64_t val = (uint64_t)n;
    uint32_t len = 0;
    while (val > 1 && len < 10000) {
        val = (val & 1) ? 3 * val + 1 : val >> 1;
        len++;
    }
    return len;
}

/* ===== CRC32-PRÜFSUMME ===== */
static uint32_t uhcs_crc32(const uint8_t *d, size_t n) {
    uint32_t c = 0xFFFFFFFF;
    for (size_t i = 0; i < n; i++) {
        c ^= d[i];
        for (int j = 0; j < 8; j++) c = (c & 1) ? (c >> 1) ^ 0xEDB88320 : c >> 1;
    }
    return ~c;
}

/* ===== FNV-1a HASH ===== */
static uint32_t fnv1a_hash(const uint8_t *data, size_t len) {
    uint32_t hash = 0x811C9DC5;
    for (size_t i = 0; i < len; i++) {
        hash ^= data[i];
        hash *= 0x01000193;
    }
    return hash;
}

/* ===== BOESING-CHECKSUMME ===== */
static uint8_t uhcs_boesing_checksum(const uint8_t *data, size_t n) {
    uint8_t sum = 0;
    for (size_t i = 0; i < n; i++) sum ^= uhcs_boesing_horner(data[i]);
    return sum;
}

/* ===== SIGMA-CHECK ===== */
static int uhcs_check_sigma(const uint8_t *data, size_t len) {
    uint32_t sum = 0;
    for (size_t i = 0; i < len; i++) sum += data[i];
    return (sum % UHCS_SIGMA == 0) ? 1 : 0;
}

