/* ╔══════════════════════════════════════════════════════════════════════════════╗
 * ║  TEIL VI: DATENSTRUKTUREN & TYP-DEFINITIONEN                              ║
 * ║  §15 Komponentenlehre: Jede Funktion ist ein Werkstein mit DNA            ║
 * ║  §18 Welt A/B: gerade/ungerade, +/-, abrunden/aufrunden                  ║
 * ╚══════════════════════════════════════════════════════════════════════════════╝ */

/* ===== WELTEN & POLARITÄTEN (§18) ===== */
typedef enum { WORLD_A = 0, WORLD_B = 1, WORLD_HYBRID = 2, WORLD_SANDBOX = 3 } WorldType;
typedef enum { POL_POS = 0, POL_NEG = 1, POL_HYBRID = 2 } PolarityType;
typedef enum { ROUND_FLOOR = 0, ROUND_CEIL = 1 } RoundingType;

/* ===== WERKSTEIN-KLASSEN (§15) ===== */
typedef enum {
    WS_KERN = 0,        /* Fundamentale Kernfunktion */
    WS_TRANSFORM,       /* Vorwärts-Transformation */
    WS_LUT,             /* Lookup-Tabelle */
    WS_INVERS,          /* Inverse/Rückwärts-Funktion */
    WS_REFERENZ,        /* Referenz-Anker (ALFONS/RUTH) */
    WS_BRUECKE,         /* Brücke zwischen Welt A und B (§16) */
    WS_SLOT,            /* Zugewiesener Slot */
    WS_BEOBACHTER,      /* Beobachter (keine Zustandsänderung) */
    WS_SIGNATUR,        /* System-Signatur */
    WS_ENERGIE,         /* Statische Energie & Balance (601-700) */
    WS_EXTERN,          /* Externe Schnittstelle (701-800) */
    WS_SCHUTZ           /* Schutz & Isolation (703, etc.) */
} WerksteinKlasse;

/* ===== FUNKTIONSWÜRDE (§26) ===== */
typedef enum {
    FW_FIXIEREND = 0,   /* Welt A: Fixierung, Stabilisierung */
    FW_RUECKFUEHREND,   /* Inversion, Dekompression */
    FW_OEFFNEND,        /* Welt B: Öffnung, Exploration */
    FW_FORTSETZEND,     /* Fortschritt, nächster Schritt */
    FW_VERMITTELND,     /* Brücke, Hybrid */
    FW_BEOBACHTEND,     /* Nur Analyse, keine Änderung */
    FW_SPIEGELND,       /* §27: Spiegelung */
    FW_INVERTIEREND,    /* §27: Inversion (≠ Spiegelung) */
    FW_BALANCIEREND,    /* Balance: Energetisches Gleichgewicht */
    FW_RESONIEREND      /* Resonanz: Externe Schwingungskopplung */
} FunktionsWuerde;

/* ===== WERKSTEIN-DNA (§15) ===== */
typedef struct {
    uint16_t         slot_id;        /* Slot 1-800 (Gronau-Register) */
    const char      *name;           /* Funktionsname */
    uint8_t          ebene;          /* Ebene 0-9 */
    WorldType        welt;           /* Welt A/B/Hybrid */
    PolarityType     polaritaet;     /* +/-/Hybrid */
    RoundingType     rundung;        /* §25: Abrunden/Aufrunden */
    WerksteinKlasse  klasse;         /* §15: Kern/Transform/... */
    FunktionsWuerde  wuerde;         /* §26: Betriebsrichtung */
    uint8_t          paritaet;       /* 0=gerade, 1=ungerade */
} WerksteinDNA;

/* ===== ANKERSTEIN (§17) ===== */
typedef struct {
    uint16_t     id;
    uint8_t      sequence[3];
    PolarityType polarity;
    WorldType    world;
} AnchorStone;

/* ===== KLASSEN-MODUL (für Pipeline) ===== */
typedef struct {
    uint16_t class_id;
    uint8_t  level;
    void (*gen_table_fwd[NUM_SLOTS])(uint8_t residual, uint8_t table[256]);
    void (*gen_table_inv[NUM_SLOTS])(uint8_t residual, uint8_t table[256]);
    uint8_t residual_xor;
} ClassModule;

/* ===== UHCS DATEI-HEADER ===== */
typedef struct {
    uint32_t magic;              /* MASTER_MAGIC = "UHCS" */
    uint16_t version;            /* Format-Version */
    uint16_t flags;              /* Kompression-Flags (niedrige 16 Bit) */
    uint32_t original_size;      /* Originalgröße */
    uint32_t compressed_size;    /* Komprimierte Größe */
    uint32_t crc32;              /* CRC32-Prüfsumme */
    uint16_t primary_series;     /* Primäre Serie-ID */
    uint16_t secondary_series;   /* Sekundäre Serie-ID */
    uint8_t  delta_order;        /* Delta-Ordnung (0-4) */
    uint8_t  predictor_mode;     /* Prädiktor-Modus */
    uint32_t security_seed;      /* Sicherheits-Seed */
    uint32_t hologram_seed;      /* Hologramm-Seed */
    uint8_t  odd_even_split;     /* Gerade/Ungerade-Trennung */
    uint8_t  music_flow;         /* Musik-Fluss-Modus */
    uint32_t extended_flags;     /* Erweiterte Flags (obere 16 Bit) */
    uint8_t  reserved[2];       /* Reserviert für Zukunft */
} uhcs_header_t;

/* ===== PIPELINE-ZUSTAND (§4 Logische Superposition) ===== */
typedef struct {
    uint32_t mask;                          /* Aktive Ebenen-Maske */
    uint32_t dir;                           /* Richtungs-Maske */
    uint8_t  snaps[UHCS_MAX_EBENEN];        /* Ebenen-Snapshots */
    uint8_t  res;                           /* Gesamt-Residual */
    uint8_t  phase;                         /* Aktuelle Phase */
    uint8_t  resonance[UHCS_MAX_EBENEN];    /* Resonanz pro Ebene */
    uint16_t class_id;                      /* Klassen-ID */
    uint8_t  work_A[UHCS_MAX_BLOCK];        /* Arbeits-Puffer A (Welt A) */
    uint8_t  work_B[UHCS_MAX_BLOCK];        /* Arbeits-Puffer B (Welt B) */
    uint8_t  residual_A;                    /* Residual Welt A */
    uint8_t  residual_B;                    /* Residual Welt B */
    uint32_t markers[8];                    /* Positions-Marker */
} uhcs_pipe_state_t;

/* ===== HOLOGRAMM (§3 Holographische Kohärenz) ===== */
typedef struct {
    uint8_t  parity_xor;     /* XOR-Parität */
    uint8_t  parity_add;     /* ADD-Parität (mod 256) */
    uint32_t crc;            /* CRC32-Sicherung */
    uint32_t seed;           /* Generierungs-Seed */
    size_t   original_size;  /* Originalgröße */
    uint8_t  checkpoints[8]; /* 8 Checkpoint-Werte */
} hologram_t;

/* ===== DNA-EINTRAG (Persistentes Lernarchiv) ===== */
typedef struct {
    uint32_t file_hash;          /* FNV-1a Hash der ersten 256 Bytes */
    uint16_t best_series[8];     /* Beste 8 Serien-IDs */
    uint8_t  file_type;          /* Dateityp (0=binär, 1=text, 2=bild, ...) */
    float    compression_ratio;  /* Erreichte Kompressionsrate */
    uint32_t usage_count;        /* Nutzungszähler */
    time_t   last_used;          /* Letzter Zugriff */
} dna_entry_t;

/* ===== RANGE-CODER (Entropie-Codierung) ===== */
typedef struct {
    uint32_t lo, range;
    uint8_t *buf;
    size_t   buf_len, pos;
    int      carry;
} rc_enc;

typedef struct {
    uint32_t lo, range, code;
    const uint8_t *buf;
    size_t   buf_len, pos;
} rc_dec;

/* ===== TASK-MODUS ===== */
typedef enum {
    TASK_COMPRESS = 0,
    TASK_DECOMPRESS,
    TASK_BENCHMARK,
    TASK_ANALYZE,
    TASK_SELF_TEST,
    TASK_IDLE
} task_mode_t;

/* ===== MUSTER-TYP (Pattern Detection) ===== */
typedef enum {
    PAT_NONE = 0,
    PAT_CONSTANT,       /* Alle Bytes gleich */
    PAT_ASCENDING,      /* Aufsteigend */
    PAT_DESCENDING,     /* Absteigend */
    PAT_PERIODIC,       /* Periodisch (Zykluslänge) */
    PAT_RUNS,           /* Viele Läufe (RLE-freundlich) */
    PAT_DIFF,           /* Differenz-Muster (Delta-freundlich) */
    PAT_TEXT,           /* Text-artig (ASCII) */
    PAT_BINARY,         /* Binär-artig (hohe Entropie) */
    PAT_MUSIC,          /* Musik-artig (harmonisch) */
    PAT_RANDOM,         /* Pseudozufällig */
    PAT_SPARSE,         /* Dünn besetzt (viele Nullen) */
    PAT_MIXED           /* Gemischt */
} PatternType;

/* ===== MUSTER-ANALYSE ===== */
