/* ===== HYBRID NIBBLE-SPLIT [Slot 060/061] =====
 * Teilt Bytes in Low-Nibble und High-Nibble */

/* Slot 060: hyb_enc [Transform, Welt A, Ebene 3] */
static void hyb_enc(const uint8_t *a, size_t n, uint8_t *lo, uint8_t *hi) {
    for (size_t i = 0; i < n; i++) {
        lo[i] = a[i] & 0x0F;
        hi[i] = (a[i] >> 4) & 0x0F;
    }
}

/* Slot 061: hyb_dec [Invers, Welt A, Ebene 3] */
static void hyb_dec(const uint8_t *lo, const uint8_t *hi, size_t n, uint8_t *out) {
    for (size_t i = 0; i < n; i++)
        out[i] = (hi[i] << 4) | (lo[i] & 0x0F);
}

/* ===== DUAL-LAYER SHIFT ===== */
static void dual_layer_shift(uint8_t *data, size_t n, int shift) {
    for (size_t i = 0; i < n; i++) {
        if (shift > 0) data[i] = (uint8_t)((data[i] << shift) | (data[i] >> (8 - shift)));
        else data[i] = (uint8_t)((data[i] >> (-shift)) | (data[i] << (8 + shift)));
    }
}

/* ===== BEREICHS-OPTIMIERUNG (AREA-FIX) [Slot 080/081] =====
 * Findet zusammenhängende Bereiche gleicher Bytes und komprimiert diese */

/* Finde besten zusammenhängenden Bereich */
static void find_best_area(const uint8_t *data, size_t n,
                           size_t *area_start, size_t *area_len, uint8_t *area_val) {
    *area_start = 0;
    *area_len = 0;
    *area_val = 0;
    size_t best_len = 0, best_start = 0;
    uint8_t best_val = 0;
    size_t i = 0;
    while (i < n) {
        size_t run = 1;
        while (i + run < n && data[i + run] == data[i]) run++;
        if (run > best_len) {
            best_len = run;
            best_start = i;
            best_val = data[i];
        }
        i += run;
    }
    *area_start = best_start;
    *area_len = best_len;
    *area_val = best_val;
}

/* Slot 080: area_fix_compress [Transform, Welt A, Ebene 2] */
static size_t area_fix_compress(const uint8_t *in, size_t n, uint8_t *out, size_t cap) {
    if (n == 0 || cap < n + 12) return 0;
    size_t area_start, area_len;
    uint8_t area_val;
    find_best_area(in, n, &area_start, &area_len, &area_val);
    if (area_len < 8) {
        /* Kein guter Bereich → kopiere unverändert */
        memcpy(out, in, n);
        return n;
    }
    /* Format: [FLAG(1)][area_val(1)][area_start(4)][area_len(4)][rest_data] */
    size_t o = 0;
    out[o++] = 0xAF; /* Area-Fix Magic */
    out[o++] = area_val;
    UHCS_WRITE_LE32(out + o, (uint32_t)area_start); o += 4;
    UHCS_WRITE_LE32(out + o, (uint32_t)area_len); o += 4;
    /* Schreibe Daten vor dem Bereich */
    if (area_start > 0) {
        memcpy(out + o, in, area_start);
        o += area_start;
    }
    /* Schreibe Daten nach dem Bereich */
    size_t after = area_start + area_len;
    if (after < n) {
        memcpy(out + o, in + after, n - after);
        o += (n - after);
    }
    return o;
}

/* Slot 081: area_fix_decompress [Invers, Welt A, Ebene 2] */
static size_t area_fix_decompress(const uint8_t *in, size_t n, uint8_t *out, size_t cap) {
    if (n < 10 || in[0] != 0xAF) {
        /* Kein Area-Fix Format → kopiere unverändert */
        if (n <= cap) { memcpy(out, in, n); return n; }
        return 0;
    }
    size_t o = 1;
    uint8_t area_val = in[o++];
    uint32_t area_start = UHCS_READ_LE32(in + o); o += 4;
    uint32_t area_len = UHCS_READ_LE32(in + o); o += 4;
    size_t total = area_start + area_len + (n - o - area_start);
    if (total > cap) return 0;
    /* Rekonstruiere: [before][area][after] */
    size_t out_pos = 0;
    if (area_start > 0 && o + area_start <= n) {
        memcpy(out, in + o, area_start);
        out_pos += area_start;
        o += area_start;
    }
    memset(out + out_pos, area_val, area_len);
    out_pos += area_len;
    if (o < n) {
        memcpy(out + out_pos, in + o, n - o);
        out_pos += (n - o);
    }
    return out_pos;
}


/* ╔══════════════════════════════════════════════════════════════════════════════╗
 * ║  TEIL XIII: LOCHBILD-SYSTEM & PRIMZAHL-RESONANZ                           ║
 * ║  (Slot 280/281 + Prime Resonance Analyzer)                                ║
 * ╚══════════════════════════════════════════════════════════════════════════════╝ */

/* ===== PRIME RESONANCE ANALYZER ===== */
static uint8_t primes_1000[168];
static int primes_initialized = 0;

static void init_primes(void) {
    if (primes_initialized) return;
    int count = 0;
    for (int n = 2; n < 1000 && count < 168; n++) {
        int is_p = 1;
        for (int d = 2; d * d <= n; d++) {
            if (n % d == 0) { is_p = 0; break; }
        }
        if (is_p) primes_1000[count++] = (uint8_t)(n % 256);
    }
    primes_initialized = 1;
}

static uint16_t uhcs_prime_resonance_analyze(const uint8_t *data, size_t n) {
    if (n < 64) return 23;
    init_primes();
    uint32_t scores[168] = {0};
    size_t limit = (n > 8192) ? 8192 : n;
    for (size_t i = 0; i < limit; i++) {
        uint8_t byte = data[i];
        for (int p = 0; p < 168; p++) {
            if (primes_1000[p] > 0 && byte % primes_1000[p] == 0) scores[p]++;
        }
    }
    uint32_t best_score = 0;
    uint8_t best_prime = 23;
    for (int p = 0; p < 168; p++) {
        if (scores[p] > best_score) {
            best_score = scores[p];
            best_prime = primes_1000[p];
        }
    }
    return (best_prime >= 1) ? best_prime : 23;
}

/* ===== SICHERE ZUFALLSZAHL ===== */
static uint32_t secure_random_32(void) {
    uint32_t r = 0;
#if defined(__linux__) && defined(SYS_getrandom)
    long ret = syscall(SYS_getrandom, &r, sizeof(r), 0);
    if (ret == (long)sizeof(r)) return r;
#endif
    FILE *f = fopen("/dev/urandom", "rb");
    if (f) {
        if (fread(&r, sizeof(r), 1, f) == 1) { fclose(f); return r; }
        fclose(f);
    }
    static uint32_t lcg_state = 0xDEADBEEF;
    lcg_state = lcg_state * 1103515245 + 12345;
    return lcg_state;
}

/* ===== LOCHBILD-GENERATION (Fisher-Yates) [Slot 280/281] ===== */
static void uhcs_lochbild_generate(uint32_t seed, uint8_t lb[256], uint8_t inv[256]) {
    for (int i = 0; i < 256; i++) lb[i] = (uint8_t)i;
    uint32_t state = seed ^ 0xDEADBEEF;
    for (int i = 255; i > 0; i--) {
        state = state * 1103515245 + 12345;
        int j = (int)((state >> 16) % (uint32_t)(i + 1));
        uint8_t tmp = lb[i]; lb[i] = lb[j]; lb[j] = tmp;
    }
    for (int i = 0; i < 256; i++) inv[lb[i]] = (uint8_t)i;
}

static int uhcs_lochbild_verify(const uint8_t lb[256], const uint8_t inv[256]) {
    uint8_t seen[256] = {0};
    for (int i = 0; i < 256; i++) {
        if (seen[lb[i]]) return 0;
        seen[lb[i]] = 1;
    }
    for (int i = 0; i < 256; i++) if (inv[lb[i]] != (uint8_t)i) return 0;
    return 1;
}

static void uhcs_lochbild_apply(const uint8_t *in, uint8_t *out, size_t n, const uint8_t lb[256]) {
    for (size_t i = 0; i < n; i++) out[i] = lb[in[i]];
}
static void uhcs_lochbild_reverse(const uint8_t *in, uint8_t *out, size_t n, const uint8_t inv[256]) {
    for (size_t i = 0; i < n; i++) out[i] = inv[in[i]];
}


/* ╔══════════════════════════════════════════════════════════════════════════════╗
 * ║  TEIL XIV: MUSTER-ERKENNUNG (Pattern Detection)                           ║
 * ║  (Slot 140)                                                               ║
 * ║  §7 Zustand vor Abstraktion — Erkennung vor Kompression                   ║
 * ╚══════════════════════════════════════════════════════════════════════════════╝ */

/* ===== RESONANZ-DETEKTOR =====
 * Erkennt Fingerabdruck-basierte Muster in Daten */

static uint32_t resonanz_fingerprint(const uint8_t *data, size_t n) {
    uint32_t fp = 0;
    for (size_t i = 0; i < n && i < 64; i++) {
        fp = fp * 31 + data[i] + (uint32_t)i;
    }
    return fp;
}

/* ===== PERIODIZITÄTS-ERKENNUNG ===== */
static uint32_t detect_period(const uint8_t *data, size_t n) {
    if (n < 8) return 0;
    for (uint32_t p = 1; p <= n / 2 && p <= 256; p++) {
        int match = 1;
        for (size_t i = p; i < n && i < p + 256; i++) {
            if (data[i] != data[i % p]) { match = 0; break; }
        }
        if (match) return p;
    }
    return 0;
}

/* ===== LAUF-ZÄHLUNG ===== */
static uint32_t count_runs(const uint8_t *data, size_t n) {
    if (n < 2) return (uint32_t)n;
    uint32_t runs = 1;
    for (size_t i = 1; i < n; i++) {
        if (data[i] != data[i - 1]) runs++;
    }
    return runs;
}

/* ===== TEXT-ERKENNUNG ===== */
static float text_ratio(const uint8_t *data, size_t n) {
    if (n == 0) return 0.0f;
    uint32_t printable = 0;
    for (size_t i = 0; i < n; i++) {
        if ((data[i] >= 0x20 && data[i] <= 0x7E) || data[i] == 0x0A || data[i] == 0x0D || data[i] == 0x09)
            printable++;
    }
    return (float)printable / (float)n;
}

/* ===== DIFFERENZ-MUSTER ===== */
static int has_diff_pattern(const uint8_t *data, size_t n) {
    if (n < 4) return 0;
    /* Prüfe ob Differenzen klein sind (gute Delta-Kandidaten) */
    uint32_t small_diffs = 0;
    for (size_t i = 1; i < n; i++) {
        int diff = (int)data[i] - (int)data[i - 1];
        if (diff < 0) diff = -diff;
        if (diff < 16) small_diffs++;
    }
    return (small_diffs > (n * 3) / 4) ? 1 : 0;
}

/* ===== SPARSENESS-CHECK ===== */
static float sparseness(const uint8_t *data, size_t n) {
    if (n == 0) return 0.0f;
    uint32_t zeros = 0;
    for (size_t i = 0; i < n; i++) if (data[i] == 0) zeros++;
    return (float)zeros / (float)n;
}

/* ===== UNIQUE BYTES ===== */
static uint32_t uhcs_unique_bytes(const uint8_t *data, size_t n) {
    uint8_t seen[256] = {0};
    for (size_t i = 0; i < n; i++) seen[data[i]] = 1;
    uint32_t count = 0;
    for (int i = 0; i < 256; i++) if (seen[i]) count++;
    return count;
}

/* Slot 140: pattern_detect [Beobachter, Hybrid, Ebene 6] */
static PatternAnalysis pattern_detect(const uint8_t *data, size_t n) {
    PatternAnalysis pa;
    memset(&pa, 0, sizeof(pa));
    if (n == 0) { pa.type = PAT_NONE; return pa; }
    pa.entropy = shannon_entropie(data, n);
    pa.unique_bytes = uhcs_unique_bytes(data, n);
    pa.run_count = count_runs(data, n);
    pa.cycle_length = detect_period(data, n);
    pa.text_ratio = text_ratio(data, n);
    /* Bestimme dominantes Byte */
    uint32_t freq[256] = {0};
    for (size_t i = 0; i < n; i++) freq[data[i]]++;
    uint32_t max_freq = 0;
    for (int i = 0; i < 256; i++) {
        if (freq[i] > max_freq) { max_freq = freq[i]; pa.dominant_byte = (uint8_t)i; }
    }
    /* Klassifiziere */
    if (pa.unique_bytes == 1) {
        pa.type = PAT_CONSTANT;
        pa.compressibility = 1.0f;
    } else if (pa.cycle_length > 0 && pa.cycle_length < n / 2) {
        pa.type = PAT_PERIODIC;
        pa.compressibility = 0.9f;
    } else if (pa.text_ratio > 0.85f) {
        pa.type = PAT_TEXT;
        pa.compressibility = 0.6f;
    } else if (has_diff_pattern(data, n)) {
        pa.type = PAT_DIFF;
        pa.compressibility = 0.7f;
    } else if (pa.run_count < n / 4) {
        pa.type = PAT_RUNS;
        pa.compressibility = 0.8f;
    } else if (sparseness(data, n) > 0.7f) {
        pa.type = PAT_SPARSE;
        pa.compressibility = 0.85f;
    } else if (pa.entropy > 7.8f) {
        pa.type = PAT_RANDOM;
        pa.compressibility = 0.02f;
    } else if (pa.entropy < 4.0f) {
        pa.type = PAT_ASCENDING;
        pa.compressibility = 0.75f;
    } else {
        pa.type = PAT_MIXED;
        pa.compressibility = 0.3f;
    }
    return pa;
}


