/* Slot 230: aes_simple_encrypt — Vereinfachte AES-artige Verschlüsselung */
static void aes_simple_encrypt(uint8_t *data, size_t n, const uint8_t key[32]) {
    /* 10 Runden mit S-Box, ShiftRows-artig, und MixColumns-artig */
    for (int round = 0; round < 10; round++) {
        uint8_t round_key = key[round % 32] ^ (uint8_t)round;
        for (size_t i = 0; i < n; i++) {
            /* SubBytes */
            data[i] = AES_SBOX[data[i]];
            /* AddRoundKey */
            data[i] ^= round_key;
            data[i] ^= key[(i + round) % 32];
            /* ShiftRows-artig: Rotiere mit Nachbar */
            if (i + 1 < n) {
                uint8_t tmp = data[i];
                data[i] = (uint8_t)((data[i] + data[i+1]) & 0xFF);
                round_key = (uint8_t)((round_key ^ tmp) + 1);
            }
        }
    }
}

/* Slot 231: aes_simple_decrypt */
static void aes_simple_decrypt(uint8_t *data, size_t n, const uint8_t key[32]) {
    for (int round = 9; round >= 0; round--) {
        uint8_t round_key = key[round % 32] ^ (uint8_t)round;
        /* Berechne Round-Keys vorwärts */
        uint8_t rkeys[UHCS_MAX_BLOCK];
        uint8_t rk = round_key;
        for (size_t i = 0; i < n; i++) {
            rkeys[i] = rk;
            rk = (uint8_t)((rk ^ data[i]) + 1);
        }
        /* Rückwärts */
        for (size_t i = n; i > 0; i--) {
            size_t idx = i - 1;
            if (idx + 1 < n) {
                data[idx] = (uint8_t)((data[idx] - data[idx+1] + 256) & 0xFF);
            }
            data[idx] ^= key[(idx + round) % 32];
            data[idx] ^= rkeys[idx];
            data[idx] = AES_INV_SBOX[data[idx]];
        }
    }
}

/* ===== MERKLE-BAUM [Slot 240/241] =====
 * Kryptographischer Hash-Baum für Integritäts-Prüfung */

typedef struct {
    uint32_t hashes[256]; /* Blatt-Hashes */
    uint32_t root;        /* Wurzel-Hash */
    size_t   num_leaves;
} MerkleTree;

/* Slot 240: merkle_build */
static MerkleTree merkle_build(const uint8_t *data, size_t n) {
    MerkleTree tree;
    memset(&tree, 0, sizeof(tree));
    size_t block_size = (n + 255) / 256;
    if (block_size == 0) block_size = 1;
    tree.num_leaves = (n + block_size - 1) / block_size;
    if (tree.num_leaves > 256) tree.num_leaves = 256;
    for (size_t i = 0; i < tree.num_leaves; i++) {
        size_t start = i * block_size;
        size_t len = block_size;
        if (start + len > n) len = n - start;
        tree.hashes[i] = uhcs_crc32(data + start, len);
    }
    /* Baue Baum aufwärts */
    uint32_t level[256];
    memcpy(level, tree.hashes, tree.num_leaves * sizeof(uint32_t));
    size_t count = tree.num_leaves;
    while (count > 1) {
        size_t new_count = (count + 1) / 2;
        for (size_t i = 0; i < new_count; i++) {
            if (2 * i + 1 < count) {
                uint8_t pair[8];
                UHCS_WRITE_LE32(pair, level[2*i]);
                UHCS_WRITE_LE32(pair + 4, level[2*i + 1]);
                level[i] = uhcs_crc32(pair, 8);
            } else {
                level[i] = level[2*i];
            }
        }
        count = new_count;
    }
    tree.root = level[0];
    return tree;
}

/* Slot 241: merkle_verify */
static int merkle_verify(const uint8_t *data, size_t n, const MerkleTree *expected) {
    MerkleTree current = merkle_build(data, n);
    return (current.root == expected->root) ? 1 : 0;
}

/* ===== INTEGRITÄTS-PRÜFUNGEN ===== */
static int uhcs_sigma_ok(void) {
    return (UHCS_A3 + UHCS_A2 + UHCS_A1 + UHCS_A0 + UHCS_GRONAUER) == UHCS_SIGMA;
}
static int uhcs_horner_verify(void) {
    for (int x = 0; x < 256; x++) {
        uint32_t t = x;
        t = ((UHCS_A3 * t + UHCS_A2) * t + UHCS_A1) * t + UHCS_A0;
        if ((uint8_t)(t & 0xFF) != MEIKEL_B_LUT[x]) return 0;
    }
    return 1;
}
static int uhcs_bijektiv_verify(void) {
    uint8_t s[256] = {0};
    for (int i = 0; i < 256; i++) {
        if (s[MEIKEL_B_LUT[i]]) return 0;
        s[MEIKEL_B_LUT[i]] = 1;
    }
    for (int i = 0; i < 256; i++)
        if (MEIKEL_B_INV[MEIKEL_B_LUT[i]] != (uint8_t)i) return 0;
    return 1;
}


/* ╔══════════════════════════════════════════════════════════════════════════════╗
 * ║  TEIL XVII: ANKER-SYSTEM (256 Ankersteine + Tesla-Anker)                  ║
 * ║  §5 Negentropie: Rekursive Anker-Kaskade E(n,k)=n/(4^k)                 ║
 * ╚══════════════════════════════════════════════════════════════════════════════╝ */

/* ===== ANKER-ERZEUGUNG ===== */
static void uhcs_generate_anchors(const uint8_t *data, size_t n,
                                  AnchorStone anchors[256], int *num_anchors) {
    *num_anchors = 0;
    if (n == 0) return;
    uint8_t phase = initial_residual(data, n);
    for (int i = 0; i < 256 && *num_anchors < 256; i++) {
        AnchorStone a;
        a.id = (uint16_t)i;
        a.sequence[0] = MEIKEL_B_LUT[i];
        a.sequence[1] = MEIKEL_B_LUT[(i + 1) & 0xFF];
        a.sequence[2] = MEIKEL_B_LUT[(i + 2) & 0xFF];
        a.polarity = (i % 2 == 0) ? POL_POS : POL_NEG;
        a.world = (i % 2 == 0) ? WORLD_A : WORLD_B;
        /* Tesla-Anker prüfen */
        for (int t = 0; t < 4; t++) {
            if ((i % 10) == TESLA_ANKER[t]) {
                a.world = WORLD_HYBRID;
                break;
            }
        }
        anchors[(*num_anchors)++] = a;
    }
    (void)phase;
}

/* ===== ANKER-KOMPRESSION =====
 * Ersetzt wiederkehrende Muster durch Anker-Referenzen */
static size_t uhcs_compress_anchors(const uint8_t *data, size_t n,
                                     uint8_t *out, size_t cap) {
    if (n == 0 || cap < n) return 0;
    AnchorStone anchors[256];
    int num_anchors = 0;
    uhcs_generate_anchors(data, n, anchors, &num_anchors);
    /* Einfache Anker-Kompression: ersetze 3-Byte-Sequenzen durch Anker-IDs */
    size_t o = 0;
    size_t i = 0;
    while (i < n && o < cap) {
        if (i + 2 < n) {
            int found = -1;
            for (int a = 0; a < num_anchors; a++) {
                if (data[i] == anchors[a].sequence[0] &&
                    data[i+1] == anchors[a].sequence[1] &&
                    data[i+2] == anchors[a].sequence[2]) {
                    found = a;
                    break;
                }
            }
            if (found >= 0) {
                out[o++] = 0xFE; /* Anker-Flag */
                out[o++] = (uint8_t)found;
                i += 3;
                continue;
            }
        }
        out[o++] = data[i++];
    }
    return o;
}

/* Anker-Expansion */
static size_t uhcs_expand_anchors(const uint8_t *data, size_t n,
                                   uint8_t *out) {
    AnchorStone anchors[256];
    int num_anchors = 0;
    uhcs_generate_anchors(data, n, anchors, &num_anchors);
    size_t o = 0;
    size_t i = 0;
    while (i < n) {
        if (data[i] == 0xFE && i + 1 < n) {
            uint8_t anchor_id = data[i + 1];
            if (anchor_id < num_anchors) {
                out[o++] = anchors[anchor_id].sequence[0];
                out[o++] = anchors[anchor_id].sequence[1];
                out[o++] = anchors[anchor_id].sequence[2];
            }
            i += 2;
        } else {
            out[o++] = data[i++];
        }
    }
    return o;
}


