/* ===== DNA-ARCHIV ===== */
#define DNA_MAX_ENTRIES 1024
static dna_entry_t dna_db[DNA_MAX_ENTRIES];
static int dna_count = 0;
static pthread_mutex_t dna_mutex = PTHREAD_MUTEX_INITIALIZER;

static const char* dna_path(void) {
    static char path[512];
    const char *home = getenv("HOME");
    if (!home) home = ".";
    snprintf(path, sizeof(path), "%s/.mb_system/dna.bin", home);
    char dir[512];
    snprintf(dir, sizeof(dir), "%s/.mb_system", home);
    mkdir(dir, 0755);
    return path;
}

/* Slot 250: dna_save [Transform, Welt A, Ebene 9] */
static void dna_save_to_disk(void) {
    pthread_mutex_lock(&dna_mutex);
    FILE *f = fopen(dna_path(), "wb");
    if (f) {
        fwrite(&dna_count, sizeof(dna_count), 1, f);
        fwrite(dna_db, sizeof(dna_entry_t), (size_t)dna_count, f);
        fclose(f);
    }
    pthread_mutex_unlock(&dna_mutex);
}

static void dna_load_from_disk(void) {
    pthread_mutex_lock(&dna_mutex);
    FILE *f = fopen(dna_path(), "rb");
    if (f) {
        int count = 0;
        if (fread(&count, sizeof(count), 1, f) == 1 && count >= 0 && count <= DNA_MAX_ENTRIES) {
            dna_count = count;
            size_t read_count = fread(dna_db, sizeof(dna_entry_t), (size_t)dna_count, f);
            if (read_count < (size_t)dna_count) dna_count = (int)read_count;
        }
        fclose(f);
    }
    pthread_mutex_unlock(&dna_mutex);
}

static uint32_t dna_hash(const uint8_t *data, size_t len) {
    return fnv1a_hash(data, (len > 256) ? 256 : len);
}

static void dna_save_entry(uint32_t hash, uint16_t *series, int series_count,
                           uint8_t file_type, float ratio) {
    pthread_mutex_lock(&dna_mutex);
    for (int i = 0; i < dna_count; i++) {
        if (dna_db[i].file_hash == hash) {
            dna_db[i].usage_count++;
            dna_db[i].compression_ratio = dna_db[i].compression_ratio * 0.7f + ratio * 0.3f;
            dna_db[i].last_used = time(NULL);
            pthread_mutex_unlock(&dna_mutex);
            dna_save_to_disk();
            return;
        }
    }
    if (dna_count < DNA_MAX_ENTRIES) {
        dna_db[dna_count].file_hash = hash;
        for (int i = 0; i < series_count && i < 8; i++)
            dna_db[dna_count].best_series[i] = series[i];
        dna_db[dna_count].file_type = file_type;
        dna_db[dna_count].compression_ratio = ratio;
        dna_db[dna_count].usage_count = 1;
        dna_db[dna_count].last_used = time(NULL);
        dna_count++;
    }
    pthread_mutex_unlock(&dna_mutex);
    dna_save_to_disk();
}

/* Slot 251: dna_recall [Beobachter, Welt A, Ebene 9] */
static uint16_t dna_recall(uint32_t hash, uint8_t file_type) {
    pthread_mutex_lock(&dna_mutex);
    for (int i = 0; i < dna_count; i++) {
        if (dna_db[i].file_hash == hash || dna_db[i].file_type == file_type) {
            uint16_t res = dna_db[i].best_series[0];
            pthread_mutex_unlock(&dna_mutex);
            return res;
        }
    }
    pthread_mutex_unlock(&dna_mutex);
    return 0;
}

/* ===== ADAPTIVE SERIEN-AUSWAHL (Intelligenz-Schicht) ===== */

/* Slot 260: intelligence_select [Kern, Hybrid, Ebene 9]
 * Wählt die beste Kombination aus Serie, Operator und Transformation */
static uint16_t adaptive_series_selection(const uint8_t *data, size_t n, uint8_t *best_score) {
    if (n < 256) return 23;
    /* Kandidaten-Serien */
    uint16_t candidates[] = {23, 58, 61, 125, 3, 36, 7, 13, 41, 77, 142, 144, 200};
    int num_candidates = (int)(sizeof(candidates)/sizeof(candidates[0]));
    float best_eff = 0.0f;
    uint16_t best_series = 23;
    size_t sample_len = (n > 4096) ? 4096 : n;
    uint8_t *sample = (uint8_t *)malloc(sample_len);
    if (!sample) return 23;
    memcpy(sample, data, sample_len);
    for (int i = 0; i < num_candidates; i++) {
        uint16_t sid = candidates[i];
        uint8_t *test_buf = (uint8_t *)malloc(sample_len);
        if (!test_buf) continue;
        memcpy(test_buf, sample, sample_len);
        for (size_t j = 0; j < sample_len; j++) {
            test_buf[j] = (test_buf[j] + series_value(sid, (uint32_t)j)) & 0xFF;
        }
        float entropy = shannon_entropie(test_buf, sample_len);
        float eff = 8.0f - entropy;
        if (eff > best_eff) {
            best_eff = eff;
            best_series = sid;
        }
        free(test_buf);
    }
    free(sample);
    if (best_score) *best_score = (uint8_t)(best_eff * 25.0f);
    return best_series;
}

/* ===== META-LERNER =====
 * Lernt über mehrere Kompressionsversuche hinweg die optimale Strategie */

typedef struct {
    uint16_t series_id;
    OperatorType op;
    int delta_order;
    int use_bwt;
    int use_lz77;   /* DEAKTIVIERT: MB-eigene Pipeline ersetzt LZ77 vollstaendig */
    float score;
} CompressionStrategy;

static CompressionStrategy meta_learn(const uint8_t *data, size_t n) {
    CompressionStrategy best;
    memset(&best, 0, sizeof(best));
    best.series_id = 23;
    best.score = 0.0f;
    if (n < 64) return best;
    PatternAnalysis pa = pattern_detect(data, n);
    /* Wähle Strategie basierend auf Muster */
    switch (pa.type) {
        case PAT_CONSTANT:
            best.series_id = 0;
            best.delta_order = 0;
            best.use_bwt = 0;
            best.use_lz77 = 0;
            best.score = 1.0f;
            break;
        case PAT_PERIODIC:
            best.series_id = (uint16_t)(pa.cycle_length % 256);
            best.op = OP_XOR;
            best.delta_order = 0;
            best.use_bwt = 0;
            best.use_lz77 = 0;
            best.score = 0.9f;
            break;
        case PAT_TEXT:
            best.series_id = 58; /* Gute Serien fuer Text */
            best.op = OP_ADD;
            best.delta_order = 0;
            best.use_bwt = 1;
            best.use_lz77 = 0;
            best.score = 0.7f;
            break;
        case PAT_DIFF:
            best.delta_order = delta_best_order(data, n);
            best.series_id = 23;
            best.op = OP_XOR;
            best.use_bwt = 0;
            best.use_lz77 = 0;
            best.score = 0.8f;
            break;
        case PAT_RUNS:
            best.series_id = 13;
            best.op = OP_ADD;
            best.delta_order = 0;
            best.use_bwt = 0;
            best.use_lz77 = 0;
            best.score = 0.85f;
            break;
        case PAT_SPARSE:
            best.series_id = 0;
            best.delta_order = 0;
            best.use_bwt = 0;
            best.use_lz77 = 0;
            best.score = 0.9f;
            break;
        default:
            best.series_id = adaptive_series_selection(data, n, NULL);
            best.op = OP_ADD;
            best.delta_order = delta_best_order(data, n);
            best.use_bwt = (pa.entropy < 6.0f) ? 1 : 0;
            best.use_lz77 = 0;
            best.score = 0.5f;
            break;
    }
    return best;
}


