/* ===== CO2-RECHNER [Slot 270] =====
 * Berechnet geschätzte CO2-Einsparung durch Kompression */

/* Annahmen:
 * - Datentransfer: 0.06 kWh/GB (Quelle: The Shift Project)
 * - Speicher: 0.005 kWh/GB/Jahr
 * - CO2/kWh: 0.4 kg (EU-Durchschnitt)
 * - Bandwidth: 100 Mbit/s */
#define CO2_KWH_PER_GB_TRANSFER  0.06
#define CO2_KWH_PER_GB_STORAGE   0.005
#define CO2_KG_PER_KWH           0.4
#define BANDWIDTH_MBPS            100.0

static CO2Result co2_calculate(size_t original, size_t compressed) {
    CO2Result r;
    memset(&r, 0, sizeof(r));
    r.bytes_original = (double)original;
    r.bytes_compressed = (double)compressed;
    r.bytes_saved = (double)(original > compressed ? original - compressed : 0);
    /* Energie */
    double gb_saved = r.bytes_saved / (1024.0 * 1024.0 * 1024.0);
    r.energy_saved_wh = gb_saved * (CO2_KWH_PER_GB_TRANSFER + CO2_KWH_PER_GB_STORAGE) * 1000.0;
    /* CO2 */
    r.co2_saved_grams = r.energy_saved_wh * CO2_KG_PER_KWH;
    /* Transfer-Zeit */
    double mbps = BANDWIDTH_MBPS;
    double bits_saved = r.bytes_saved * 8.0;
    r.transfer_time_saved = bits_saved / (mbps * 1000000.0);
    return r;
}

static void co2_print(const CO2Result *r) {
    printf("=== CO2-Analyse ===\n");
    printf("  Original:     %.0f Bytes\n", r->bytes_original);
    printf("  Komprimiert:  %.0f Bytes\n", r->bytes_compressed);
    printf("  Gespart:      %.0f Bytes (%.1f%%)\n", r->bytes_saved,
           r->bytes_original > 0 ? (r->bytes_saved / r->bytes_original * 100.0) : 0.0);
    printf("  Energie:      %.4f Wh gespart\n", r->energy_saved_wh);
    printf("  CO2:          %.4f g eingespart\n", r->co2_saved_grams);
    printf("  Transferzeit: %.6f s gespart\n", r->transfer_time_saved);
}

/* ===== STATISTIK-UPDATE ===== */
static void stats_update_compress(size_t in_bytes, size_t out_bytes) {
    pthread_mutex_lock(&stats_mutex);
    global_stats.total_bytes_in += in_bytes;
    global_stats.total_bytes_out += out_bytes;
    global_stats.compress_count++;
    double ratio = (in_bytes > 0) ? (double)in_bytes / (double)out_bytes : 1.0;
    if (ratio > global_stats.best_ratio) global_stats.best_ratio = ratio;
    if (global_stats.worst_ratio == 0.0 || ratio < global_stats.worst_ratio)
        global_stats.worst_ratio = ratio;
    global_stats.avg_ratio = (global_stats.avg_ratio * (global_stats.compress_count - 1) + ratio) /
                              global_stats.compress_count;
    global_stats.last_use = time(NULL);
    if (global_stats.first_use == 0) global_stats.first_use = global_stats.last_use;
    pthread_mutex_unlock(&stats_mutex);
}

static void stats_print(void) {
    printf("=== MB-SYSTEM Statistik ===\n");
    printf("  Kompressionen:   %u\n", global_stats.compress_count);
    printf("  Dekompressionen: %u\n", global_stats.decompress_count);
    printf("  Bytes rein:      %lu\n", (unsigned long)global_stats.total_bytes_in);
    printf("  Bytes raus:      %lu\n", (unsigned long)global_stats.total_bytes_out);
    printf("  Beste Ratio:     %.2fx\n", global_stats.best_ratio);
    printf("  Schlechteste:    %.2fx\n", global_stats.worst_ratio);
    printf("  Durchschnitt:    %.2fx\n", global_stats.avg_ratio);
    printf("  Fehler:          %u\n", global_stats.error_count);
}


