/* TEIL LXXIV: Farbkohaerenz-Synchronisation & Harmonie-Pruefung (§134/§135/§136) */
/* §134 Farb-Identitaets-Anker: Farbe=Zustand=Ebene, kein Wechsel, kein Springen */
/* §135 Tesla-Takt-Synchronisation: 0-3-6-9 als CPU-Takt-Anker, Locality of Reference */
/* §136 Hybrid-Harmonie-Pruefung: Farbe+Takt+256Formen=Einheit, kein Beissen */

typedef struct {
    uint8_t  ebene;                 /* 0..10 */
    MutterspracheFarbe farbe;       /* feste Farbzuweisung */
    uint8_t  welt;                  /* 0=A, 1=B */
    uint8_t  paritaet;              /* gerade=A, ungerade=B */
    uint8_t  kohaerenz_ok;          /* 1 wenn Farbe↔Welt↔Paritaet konsistent */
} FarbEbenenAnker;

typedef struct {
    uint8_t  position;              /* 0,3,6,9 */
    const char *name;               /* "START","BRUECKE","SPIEGEL","VOLLENDUNG" */
    uint8_t  byte_anker;            /* Referenz-Byte an dieser Position */
    uint8_t  lut_wert;              /* MEIKEL_B_LUT[byte_anker] */
    uint8_t  resonanz;              /* Resonanz zum Gronauer-Anker */
} TeslaTaktAnker;

typedef struct {
    FarbEbenenAnker farb_anker[11]; /* Ebene 0..10 */
    TeslaTaktAnker  tesla_anker[4]; /* Position 0,3,6,9 */
    uint8_t  farb_kohaerenz_gesamt; /* 1 wenn alle 11 Ebenen koharent */
    uint8_t  tesla_sync_ok;         /* 1 wenn alle 4 Takt-Anker stabil */
    uint8_t  formen_paritaet_ok;    /* 1 wenn 256 Formen paritaets-rein */
    uint8_t  hybrid_harmonie;       /* 1 wenn Farbe+Takt+Formen=Einheit */
    uint8_t  locality_score;        /* 0-255: Nah-beieinander-Guete */
    uint32_t harmonie_siegel;       /* CRC-Siegel ueber gesamte Pruefung */
    uint8_t  welt_a_rein;           /* 1 wenn gerade Bytes nur in Welt A */
    uint8_t  welt_b_rein;           /* 1 wenn ungerade Bytes nur in Welt B */
    uint8_t  kein_beissen;          /* 1 wenn keine Welt-Farb-Kollision */
    uint32_t formen_tesla_verteilung[4]; /* Formen pro Tesla-Gruppe */
} HarmonieErgebnis;

static HarmonieErgebnis mb_harmonie_pruefen(void);
static void mb_harmonie_print(const HarmonieErgebnis *h);
static uint8_t mb_farb_kohaerenz_ebene(uint8_t ebene);
