    uint32_t t9_verdichtungs_ratio;  /* Speicherersparnis in Promille */
    uint8_t  codierung_funktion_ok;  /* 1 wenn Codierung↔Funktion abgestimmt */
    uint8_t  speicher_reduktion_ok;  /* 1 wenn T9-Gruppen effizient */
    uint8_t  abstimmung_bewiesen;    /* 1 wenn Codierung+Funktion+Speicher kohaerent */
