/* ─── TEIL CCIII: ABSTANDS-KOMPRESSOR (§453) ───────────────────────────── */
/* Aus AbstandsKompressor (v28): Findet regelmäßige Abstände zwischen
 * gleichen Bytes. Kodiert als (Wert, Abstand, Wiederholungen). */
typedef struct {
    uint8_t wert;
    uint16_t abstand;
    uint16_t wiederholungen;
} AbstandsMuster;

static int mb_abstands_analyse(const uint8_t *daten, size_t n, AbstandsMuster *out, int max_muster) {
    if (n < 4) return 0;
    int gefunden = 0;
    for (uint16_t abstand = 1; abstand <= 16 && abstand < n / 2; abstand++) {
        for (size_t i = 0; i + abstand < n; i++) {
            if (daten[i] == daten[i + abstand]) {
                /* Wie oft setzt sich das fort? */
                uint16_t wdh = 1;
                size_t j = i;
                while (j + abstand < n && daten[j] == daten[j + abstand]) {
                    wdh++;
                    j += abstand;
                    if (wdh > 1000) break;
                }
                if (wdh >= 3 && gefunden < max_muster) {
                    out[gefunden].wert = daten[i];
                    out[gefunden].abstand = abstand;
                    out[gefunden].wiederholungen = wdh;
                    gefunden++;
                }
            }
        }
    }
    return gefunden;
}

/* ─── TEIL CCIV: RANGE-CODER (§454) ────────────────────────────────────── */
/* Aus RangeCoder (v28): Arithmetische Kodierung im Wertebereich.
 * (Simplifizierte Variante - der echte Range-Coder ist in TEIL XCVIII.) */
typedef struct {
    uint64_t low;
    uint32_t range;
    uint8_t *out;
    size_t out_pos;
    size_t out_cap;
} MBRangeCoder;

static void mb_rangecoder_init(MBRangeCoder *rc, uint8_t *out, size_t cap) {
    rc->low = 0;
    rc->range = 0xFFFFFFFF;
    rc->out = out;
    rc->out_pos = 0;
    rc->out_cap = cap;
}

static void mb_rangecoder_encode(MBRangeCoder *rc, uint32_t kum_low, uint32_t kum_range, uint32_t total) {
    rc->range /= total;
    rc->low += kum_low * rc->range;
    rc->range *= kum_range;
    while ((rc->low ^ (rc->low + rc->range)) < (1U << 24)) {
        if (rc->out_pos < rc->out_cap) rc->out[rc->out_pos++] = (uint8_t)(rc->low >> 24);
        rc->low <<= 8;
        rc->range <<= 8;
    }
}

/* ─── TEIL CCV: CONTEXT-MIXING-MODEL (§455) ────────────────────────────── */
/* Aus ContextMixingModel (v28): mischt Vorhersagen mehrerer Kontexte. */
typedef struct {
    uint32_t kontext_haeufigkeit[16][256];   /* 16 Kontext-Slots */
} MBContextMixer;

static void mb_context_mixer_init(MBContextMixer *cm) {
    memset(cm->kontext_haeufigkeit, 0, sizeof(cm->kontext_haeufigkeit));
}

static void mb_context_mixer_update(MBContextMixer *cm, uint8_t kontext, uint8_t byte) {
    cm->kontext_haeufigkeit[kontext & 0x0F][byte]++;
}

static uint8_t mb_context_mixer_predict(const MBContextMixer *cm, uint8_t kontext) {
    uint8_t k = kontext & 0x0F;
    uint8_t beste = 0;
    uint32_t maxh = 0;
    for (int b = 0; b < 256; b++) {
        if (cm->kontext_haeufigkeit[k][b] > maxh) {
            maxh = cm->kontext_haeufigkeit[k][b];
            beste = (uint8_t)b;
        }
    }
    return beste;
}

/* ─── TEIL CCVI: FRAKTAL-KOMPRESSOR (§456) ─────────────────────────────── */
/* Aus FraktalKompressor (v28): findet selbstähnliche Strukturen.
 * Speichert nur Block-Position + Skala statt Daten. */
typedef struct {
    uint16_t basis_position;
    uint16_t basis_laenge;
    uint8_t  skala;
    uint16_t ziel_position;
} FraktalReferenz;

static int mb_fraktal_finden(const uint8_t *daten, size_t n, FraktalReferenz *out, int max) {
    if (n < 16) return 0;
    int gefunden = 0;
    /* Suche identische 8-Byte-Blöcke an verschiedenen Positionen */
    for (size_t i = 0; i + 8 < n && gefunden < max; i += 8) {
        for (size_t j = i + 8; j + 8 < n; j++) {
            if (memcmp(daten + i, daten + j, 8) == 0) {
                out[gefunden].basis_position = (uint16_t)i;
                out[gefunden].basis_laenge = 8;
                out[gefunden].skala = 1;
                out[gefunden].ziel_position = (uint16_t)j;
                gefunden++;
                break;
            }
        }
    }
    return gefunden;
}

/* ─── TEIL CCVII: FOURIER-PERIODEN-ANALYSE (§457) ──────────────────────── */
/* Aus FourierPeriodenAnalyse (v28): Erkennt Periodizität via einfacher
 * DFT auf Real-Werten (kein FFT, da Block klein). */
typedef struct {
    int dominante_periode;
    double staerke;
} FourierErgebnis;

static FourierErgebnis mb_fourier_schnell(const uint8_t *daten, size_t n) {
    FourierErgebnis fr = {0, 0.0};
    if (n < 16) return fr;
    
    double max_betrag = 0.0;
    for (int p = 2; p <= (int)(n / 2) && p <= 64; p++) {
        double re = 0.0, im = 0.0;
        for (size_t i = 0; i < n; i++) {
            double winkel = 2.0 * 3.14159265 * (double)i / (double)p;
            re += daten[i] * cos(winkel);
            im -= daten[i] * sin(winkel);
        }
        double betrag = sqrt(re*re + im*im);
        if (betrag > max_betrag) {
            max_betrag = betrag;
            fr.dominante_periode = p;
            fr.staerke = betrag;
        }
    }
    return fr;
}

/* ─── TEIL CCVIII: ADRESS-KOMPRESSOR (§458) ────────────────────────────── */
/* Aus AdresspaketKompressor (v28): testet 256 Serien gegen den Block,
 * speichert nur Serien-ID + Startposition + Korrekturen. */
typedef struct {
    uint8_t serie_id;
    uint8_t start_position;
    uint16_t korrekturen;
    float ratio;
} AdressErgebnis;

static AdressErgebnis mb_adresspaket_finden(const uint8_t *daten, size_t n) {
    AdressErgebnis a;
    a.serie_id = 0; a.start_position = 0; a.korrekturen = (uint16_t)n; a.ratio = 1.0f;
    if (n < 8) return a;
    
    /* Teste BoesingFolge (Serie 0) und Variations */
    for (int sid = 0; sid < 8; sid++) {
        for (int sp = 0; sp < 256; sp += 32) {
            uint16_t fehler = 0;
            uint8_t wert = (uint8_t)sp;
            for (size_t i = 0; i < n && fehler < a.korrekturen; i++) {
                if (daten[i] != wert) fehler++;
                wert = MEIKEL_B_LUT[wert];
            }
            if (fehler < a.korrekturen) {
                a.serie_id = (uint8_t)sid;
                a.start_position = (uint8_t)sp;
                a.korrekturen = fehler;
            }
        }
    }
    a.ratio = (float)n / (float)(2 + a.korrekturen * 2);  /* serie+start + 2*korr */
    return a;
}

/* ─── TEIL CCIX: DIFFERENZ-KETTEN-CODEBUCH (§459) ──────────────────────── */
/* Aus DifferenzKettenCodebuch (v28): baut Codebuch der häufigsten Differenz-Sequenzen. */
#define MB_DIFFKETTE_MAX 64
typedef struct {
    int8_t kette[8];
    uint8_t laenge;
    uint32_t haeufigkeit;
} DiffKettenEintrag;

static int mb_diffketten_codebuch(const uint8_t *daten, size_t n, DiffKettenEintrag *out) {
    if (n < 16) return 0;
    int gef = 0;
    /* Sammle 4-Differenz-Ketten */
    for (size_t i = 0; i + 4 < n && gef < MB_DIFFKETTE_MAX; i++) {
        int8_t k[4];
        for (int j = 0; j < 4; j++) k[j] = (int8_t)((int)daten[i+j+1] - (int)daten[i+j]);
        /* Schon im Codebuch? */
        int idx = -1;
        for (int e = 0; e < gef; e++) {
            if (memcmp(out[e].kette, k, 4) == 0 && out[e].laenge == 4) { idx = e; break; }
        }
        if (idx >= 0) out[idx].haeufigkeit++;
        else {
            memcpy(out[gef].kette, k, 4);
            out[gef].laenge = 4;
            out[gef].haeufigkeit = 1;
            gef++;
        }
    }
    return gef;
}

/* ─── TEIL CCX: ANKER-CACHE (§460) ─────────────────────────────────────── */
/* Aus AnkerCache (v28): cached Anker-Sucheergebnisse. */
typedef struct {
    uint8_t anker_bytes[4];
    uint64_t letzte_pos;
    uint64_t letzter_zugriff;
    uint8_t belegt;
} AnkerCacheEintrag;

#define MB_ANKER_CACHE_GROESSE 64
static AnkerCacheEintrag mb_anker_cache[MB_ANKER_CACHE_GROESSE];
static uint64_t mb_anker_cache_takt = 0;

static void mb_anker_cache_speichern(const uint8_t anker[4], uint64_t pos) {
    int idx = 0;
    uint64_t aelteste = UINT64_MAX;
    for (int i = 0; i < MB_ANKER_CACHE_GROESSE; i++) {
        if (mb_anker_cache[i].belegt && memcmp(mb_anker_cache[i].anker_bytes, anker, 4) == 0) {
            mb_anker_cache[i].letzte_pos = pos;
            mb_anker_cache[i].letzter_zugriff = ++mb_anker_cache_takt;
            return;
        }
        if (mb_anker_cache[i].letzter_zugriff < aelteste) {
            aelteste = mb_anker_cache[i].letzter_zugriff;
            idx = i;
        }
    }
    memcpy(mb_anker_cache[idx].anker_bytes, anker, 4);
    mb_anker_cache[idx].letzte_pos = pos;
    mb_anker_cache[idx].letzter_zugriff = ++mb_anker_cache_takt;
    mb_anker_cache[idx].belegt = 1;
}

static int mb_anker_cache_suchen(const uint8_t anker[4], uint64_t *pos_out) {
    for (int i = 0; i < MB_ANKER_CACHE_GROESSE; i++) {
        if (mb_anker_cache[i].belegt && memcmp(mb_anker_cache[i].anker_bytes, anker, 4) == 0) {
            *pos_out = mb_anker_cache[i].letzte_pos;
            mb_anker_cache[i].letzter_zugriff = ++mb_anker_cache_takt;
            return 1;
        }
    }
    return 0;
}

/* ─── TEIL CCXI: DUAL-LAYER-ENGINE (§461) ──────────────────────────────── */
/* Aus DualLayerEngine (v28): Lupe-auf-Lupe-Prinzip. Anwendung der Pipeline
 * auf das Ergebnis der ersten Pipeline. */
typedef struct {
    size_t orig_groesse;
    size_t schicht1_groesse;
    size_t schicht2_groesse;
    float gesamt_ratio;
} DualLayerErgebnisV2;

static DualLayerErgebnisV2 mb_dual_layer_messen(size_t orig, size_t s1, size_t s2) {
    DualLayerErgebnisV2 dl;
    dl.orig_groesse = orig;
    dl.schicht1_groesse = s1;
    dl.schicht2_groesse = s2;
    dl.gesamt_ratio = s2 > 0 ? (float)orig / (float)s2 : 0.0f;
    return dl;
}

/* ─── TEIL CCXII: SYMMETRISCHE-FOLGE (§462) ────────────────────────────── */
/* Aus SymmetrischeFolge (v28): erzeugt symmetrische Folgen um einen Mittelwert. */
static int mb_symmetrische_folge_check(const uint8_t *daten, size_t n) {
    if (n < 4) return 0;
    /* Test: ist es ein Palindrom oder spiegelsymmetrisch? */
    uint8_t mittel = daten[n/2];
    int sym_treffer = 0;
    for (size_t i = 0; i < n / 2; i++) {
        if ((int)daten[i] + (int)daten[n-1-i] == 2 * (int)mittel) sym_treffer++;
    }
    return (int)((100 * sym_treffer) / (n / 2));
}

/* ─── TEIL CCXIII: ALGEBRAIC-COMPRESSOR (§463) ─────────────────────────── */
/* Aus AlgebraicCompressor (v28): findet algebraische Beziehung zwischen Werten. */
typedef struct {
    int konstante;
    int linear_a;          /* daten[i] = linear_a * i + konstante */
    uint8_t passt;
} AlgebraischeBeziehung;

static AlgebraischeBeziehung mb_algebra_finden(const uint8_t *daten, size_t n) {
    AlgebraischeBeziehung a = {0, 0, 0};
    if (n < 3) return a;
    int diff = (int)daten[1] - (int)daten[0];
    int ok = 1;
    for (size_t i = 1; i < n; i++) {
        int erwartet = ((int)daten[0] + (int)diff * (int)i) & 0xFF;
        if ((int)daten[i] != erwartet) { ok = 0; break; }
    }
    if (ok) {
        a.konstante = daten[0];
        a.linear_a = diff;
        a.passt = 1;
    }
    return a;
}

/* ─── TEIL CCXIV: BIDIREKTIONALER-KOMPRESSOR (§464) ────────────────────── */
/* Aus BidirektionalerKompressor (v28): testet vorwärts und rückwärts. */
static int mb_bidirektional_besser(const uint8_t *daten, size_t n) {
    /* Welche Richtung hat mehr BoesingFolge-Treffer? */
    int vor = 0, rueck = 0;
    for (size_t i = 1; i < n; i++) {
        if (daten[i] == MEIKEL_B_LUT[daten[i-1]]) vor++;
        if (daten[i-1] == MEIKEL_B_LUT[daten[i]]) rueck++;
    }
    return vor >= rueck ? 0 : 1;  /* 0 = vorwärts, 1 = rückwärts */
}

/* ─── TEIL CCXV: INKREMENTELLER-KOMPRESSOR (§465) ──────────────────────── */
/* Aus IncrementalCompressor (v28): kann Stream häppchenweise verarbeiten. */
typedef struct {
    uint64_t bytes_verarbeitet;
    uint64_t bytes_ausgegeben;
    uint8_t letzter_byte;
    uint16_t aktuelle_kette;
} InkrementellState;

static void mb_inkrement_init(InkrementellState *s) {
    memset(s, 0, sizeof(*s));
}

static void mb_inkrement_byte(InkrementellState *s, uint8_t b) {
    if (b == MEIKEL_B_LUT[s->letzter_byte]) {
        s->aktuelle_kette++;
    } else {
        if (s->aktuelle_kette > 3) {
            /* Resonanz beendet, hier würde Vektor geschrieben */
            s->bytes_ausgegeben += 4;
        } else {
            s->bytes_ausgegeben += s->aktuelle_kette + 1;
        }
        s->aktuelle_kette = 0;
    }
    s->letzter_byte = b;
    s->bytes_verarbeitet++;
}

/* ─── TEIL CCXVI: MUSTER-GEDÄCHTNIS (§466) ─────────────────────────────── */
/* Aus MusterGedaechtnis (v28): Cache von erkannten Mustern. */
typedef struct {
    uint64_t signatur;
    uint8_t muster_typ;
    uint16_t laenge;
    uint64_t letzter_zugriff;
} MusterCache;

#define MB_MUSTER_CACHE 32
static MusterCache mb_muster_cache_arr[MB_MUSTER_CACHE];
static uint64_t mb_muster_cache_takt = 0;

static void mb_muster_cache_eintragen(uint64_t sig, uint8_t typ, uint16_t laenge) {
    int idx = 0;
    uint64_t aelt = UINT64_MAX;
    for (int i = 0; i < MB_MUSTER_CACHE; i++) {
        if (mb_muster_cache_arr[i].signatur == sig) {
            mb_muster_cache_arr[i].letzter_zugriff = ++mb_muster_cache_takt;
            return;
        }
        if (mb_muster_cache_arr[i].letzter_zugriff < aelt) {
            aelt = mb_muster_cache_arr[i].letzter_zugriff;
            idx = i;
        }
    }
    mb_muster_cache_arr[idx].signatur = sig;
    mb_muster_cache_arr[idx].muster_typ = typ;
    mb_muster_cache_arr[idx].laenge = laenge;
    mb_muster_cache_arr[idx].letzter_zugriff = ++mb_muster_cache_takt;
}

/* ─── TEIL CCXVII: GOLDENER-KERN-666 (§467) ────────────────────────────── */
/* Aus GoldenerKern666 (v28): Kompression mit Goldenem-Schnitt-Anker. */
static const uint8_t MB_GOLDEN_ANKER = 162;  /* phi*100 mod 256 */

static uint32_t mb_golden_resonanz(const uint8_t *daten, size_t n) {
    uint32_t resonanz = 0;
    for (size_t i = 0; i < n; i++) {
        uint8_t diff = (daten[i] > MB_GOLDEN_ANKER) ? daten[i] - MB_GOLDEN_ANKER : MB_GOLDEN_ANKER - daten[i];
        if (diff < 8) resonanz++;
    }
    return resonanz;
}

/* ─── TEIL CCXVIII: KASKADEN-KOMPRESSOR (§468) ─────────────────────────── */
/* Aus KaskadenKompressor (v28): wendet n Stufen rekursiv an. */
typedef struct {
    uint8_t stufen_aktiv;
    size_t groessen[8];
    float ratios[8];
    float gesamt_ratio;
} KaskadenErgebnis;

static KaskadenErgebnis mb_kaskaden_messen(size_t orig, const size_t *stufen_groessen, uint8_t n_stufen) {
    KaskadenErgebnis k;
    memset(&k, 0, sizeof(k));
    k.stufen_aktiv = n_stufen > 8 ? 8 : n_stufen;
    size_t letzte = orig;
    for (uint8_t i = 0; i < k.stufen_aktiv; i++) {
        k.groessen[i] = stufen_groessen[i];
        k.ratios[i] = letzte > 0 ? (float)letzte / stufen_groessen[i] : 0.0f;
        letzte = stufen_groessen[i];
    }
    k.gesamt_ratio = letzte > 0 ? (float)orig / letzte : 0.0f;
    return k;
}

/* ─── TEIL CCXIX: EVOLUTIONARY-DICTIONARY (§469) ───────────────────────── */
/* Aus EvolutionaryDictionary (v28): lernt Wörterbuch über Zeit. */
typedef struct {
    uint8_t wort[16];
    uint8_t laenge;
    uint32_t haeufigkeit;
    uint64_t erste_sichtung;
} WoerterbuchEintrag;

#define MB_WB_GROESSE 256
static WoerterbuchEintrag mb_wb[MB_WB_GROESSE];
static uint16_t mb_wb_anzahl = 0;
static uint64_t mb_wb_takt = 0;

static void mb_wb_eintragen(const uint8_t *wort, uint8_t laenge) {
    if (laenge > 16) laenge = 16;
    /* Schon drin? */
    for (int i = 0; i < mb_wb_anzahl; i++) {
        if (mb_wb[i].laenge == laenge && memcmp(mb_wb[i].wort, wort, laenge) == 0) {
            mb_wb[i].haeufigkeit++;
            return;
        }
    }
    /* Neu */
    if (mb_wb_anzahl >= MB_WB_GROESSE) {
        /* Ersetze niedrigste Häufigkeit */
        int min_idx = 0;
        for (int i = 1; i < MB_WB_GROESSE; i++) {
            if (mb_wb[i].haeufigkeit < mb_wb[min_idx].haeufigkeit) min_idx = i;
        }
        memcpy(mb_wb[min_idx].wort, wort, laenge);
        mb_wb[min_idx].laenge = laenge;
        mb_wb[min_idx].haeufigkeit = 1;
        mb_wb[min_idx].erste_sichtung = ++mb_wb_takt;
    } else {
        memcpy(mb_wb[mb_wb_anzahl].wort, wort, laenge);
        mb_wb[mb_wb_anzahl].laenge = laenge;
        mb_wb[mb_wb_anzahl].haeufigkeit = 1;
        mb_wb[mb_wb_anzahl].erste_sichtung = ++mb_wb_takt;
        mb_wb_anzahl++;
    }
}

/* ─── TEIL CCXX: META-LEARNER-V2 (§470) ────────────────────────────────── */
/* Aus MetaLearnerV2 (v28): Q-Learning für Pipeline-Wahl. */
typedef struct {
    float q_werte[16][8];   /* 16 Datentypen x 8 Pipelines */
} MetaLernerV2;

static MetaLernerV2 mb_meta_lerner;

static void mb_meta_lerner_init(void) {
    for (int i = 0; i < 16; i++)
        for (int j = 0; j < 8; j++)
            mb_meta_lerner.q_werte[i][j] = 0.5f;
}

static void mb_meta_lerner_belohnen(uint8_t datentyp, uint8_t pipeline, float ratio) {
    float alpha = 0.1f;  /* Lernrate */
    uint8_t dt = datentyp & 0x0F;
    uint8_t pp = pipeline & 0x07;
    mb_meta_lerner.q_werte[dt][pp] += alpha * (ratio - mb_meta_lerner.q_werte[dt][pp]);
}

static uint8_t mb_meta_lerner_beste_pipeline(uint8_t datentyp) {
    uint8_t dt = datentyp & 0x0F;
    uint8_t beste = 0;
    float max = mb_meta_lerner.q_werte[dt][0];
    for (int p = 1; p < 8; p++) {
        if (mb_meta_lerner.q_werte[dt][p] > max) {
            max = mb_meta_lerner.q_werte[dt][p];
            beste = (uint8_t)p;
        }
    }
    return beste;
}

/* ─── TEIL CCXXI: SERIEN-ALPHABET (§471) ───────────────────────────────── */
