/* ─── TEIL CCXXV: TRANSFORM-PIPELINE-SEARCHER (§475) ───────────────────── */
/* Aus TransformPipelineSearcher (v28): probiert Pipeline-Kombinationen. */
typedef struct {
    uint8_t schritte[8];   /* Welche Transformationen */
    uint8_t anzahl_schritte;
    float beste_ratio;
} PipelineFund;

static PipelineFund mb_pipeline_suchen(const uint8_t *daten, size_t n) {
    PipelineFund p;
    memset(&p, 0, sizeof(p));
    if (n < 16) return p;
    
    /* Heuristik: welche Schritte machen Sinn? */
    EntropieVorhersage ev = mb_entropie_vorhersage(daten, n);
    p.beste_ratio = 1.0f;
    p.anzahl_schritte = 0;
    
    if (ev.entropie_pro_byte < 7.0) {
        p.schritte[p.anzahl_schritte++] = 1;  /* BWT */
        p.schritte[p.anzahl_schritte++] = 2;  /* MTF */
    }
    if (ev.entropie_pro_byte < 6.0) {
        p.schritte[p.anzahl_schritte++] = 3;  /* RLE */
    }
    p.schritte[p.anzahl_schritte++] = 4;     /* Range-Coder */
    
    p.beste_ratio = (float)(8.0 / ev.entropie_pro_byte);
    return p;
}

/* ─── TEIL CCXXVI: GLOBAL-DEDUPLIKATOR (§476) ──────────────────────────── */
/* Aus GlobalerDeduplikator (v28): findet identische Blöcke über die Datei. */
typedef struct {
    uint64_t block_hash;
    uint16_t erste_position;
    uint8_t belegt;
} DedupEintrag;

#define MB_DEDUP_GROESSE 512
static DedupEintrag mb_dedup[MB_DEDUP_GROESSE];

static int mb_dedup_zaehlen(const uint8_t *daten, size_t n, uint16_t block_groesse) {
    if (n < block_groesse * 2) return 0;
    memset(mb_dedup, 0, sizeof(mb_dedup));
    int duplikate = 0;
    
    for (size_t i = 0; i + block_groesse <= n; i += block_groesse) {
        uint64_t h = 14695981039346656037ULL;
        for (uint16_t j = 0; j < block_groesse; j++) {
            h = (h ^ daten[i + j]) * 1099511628211ULL;
        }
        int slot = (int)(h % MB_DEDUP_GROESSE);
        for (int k = 0; k < 4; k++) {
            int idx = (slot + k) % MB_DEDUP_GROESSE;
            if (!mb_dedup[idx].belegt) {
                mb_dedup[idx].block_hash = h;
                mb_dedup[idx].erste_position = (uint16_t)(i / block_groesse);
                mb_dedup[idx].belegt = 1;
                break;
            } else if (mb_dedup[idx].block_hash == h) {
                duplikate++;
                break;
            }
        }
    }
    return duplikate;
}

/* ─── TEIL CCXXVII: HYBRID-KOMPRESSOR (§477) ───────────────────────────── */
/* Aus HybridKompressor (v28): kombiniert mehrere Strategien intelligent. */
typedef struct {
    uint8_t verwendete_pipeline;
    uint8_t fallback_aktiv;
    float effizienz_score;
} HybridErgebnis;

static HybridErgebnis mb_hybrid_strategie(const uint8_t *daten, size_t n) {
    HybridErgebnis h;
    memset(&h, 0, sizeof(h));
    if (n < 16) {
        h.fallback_aktiv = 1;
        h.effizienz_score = 0.5f;
        return h;
    }
    
    EntropieVorhersage ev = mb_entropie_vorhersage(daten, n);
    
    /* Datentyp-Routing */
    MB_Dateityp typ = mb_typ_erkennen(daten, n);
    
    if (typ == MB_TYP_KOMPRIMIERT || typ == MB_TYP_BILD || typ == MB_TYP_AUDIO) {
        h.verwendete_pipeline = 0;  /* Bypass */
        h.fallback_aktiv = 0;
        h.effizienz_score = 1.0f;
    } else if (ev.entropie_pro_byte < 1.0) {
        h.verwendete_pipeline = 1;  /* RLE-only */
        h.effizienz_score = 0.95f;
    } else if (ev.entropie_pro_byte < 4.0) {
        h.verwendete_pipeline = 2;  /* BWT+MTF+RC */
        h.effizienz_score = 0.85f;
    } else if (ev.entropie_pro_byte < 6.5) {
        h.verwendete_pipeline = 3;  /* Voll-Pipeline */
        h.effizienz_score = 0.75f;
    } else {
        h.verwendete_pipeline = 4;  /* Adaptive */
        h.effizienz_score = 0.6f;
    }
    return h;
}


