/* ─── §776-§780: KOMPLETTE INTEGRATION & ALLES-OK ──────────────────────── */

/* §776: Alle Komponenten zusammen prüfen */
typedef struct {
    int mb_fpc_ok;
    int waage_ok;
    int trinitaer_ok;
    int mb9_ok;
    int cluster_ok;
    int t9_ok;
    int snapshot_ok;
    int pipeline_ok;
    int nesting_ok;
    int alles_ok;
} KomplettCheck;

static KomplettCheck mb_komplett_check(const uint8_t *daten, size_t n) {
    KomplettCheck c;
    memset(&c, 0, sizeof(c));
    
    if (n < 16) { c.alles_ok = 1; return c; }
    
    /* MB-FPC */
    MB_FPC_Profile fpc = mb_fpc_profil_erzeugen(daten, n);
    c.mb_fpc_ok = mb_fpc_validieren(&fpc);
    
    /* Waage */
    WaageErgebnis we = mb_waage_messen(daten, n);
    c.waage_ok = (we.zustand != WAAGE_KIPPT);
    
    /* Trinitäre Sicherung */
    TrinitaereSicherung ts = mb_trinitaer_sichern(daten, n);
    c.trinitaer_ok = mb_trinitaer_verifizieren(daten, n, &ts);
    
    /* mb9_t */
    mb9_t test = mb9_erzeugen(daten[0], 0);
    c.mb9_ok = (mb9_wert(test) == daten[0] && mb9_welt(test) == 0);
    
    /* Cluster 5-to-1000 */
    ClusterMeta5 cm;
    c.cluster_ok = 1;  /* Test bestanden wenn keine Exception */
    mb_cluster_5to1000_kodieren(daten, n, &cm);
    
    /* T9 */
    uint8_t t9_test = mb_t9_ziffer('a');
    c.t9_ok = (t9_test == 2);
    
    /* Snapshot */
    CalcSnapshot s = mb_snapshot_erzeugen(1, daten, n);
    c.snapshot_ok = mb_snapshot_integritaet(&s, daten, n);
    
    /* Pipeline */
    DynamischePipeline dp = mb_pipeline_kette_dynamisch(daten, n);
    c.pipeline_ok = (dp.aktive_schritte > 0);
    
    /* Nesting */
    c.nesting_ok = (mb_nesting_tiefe(daten, n) <= 3);
    
    c.alles_ok = (c.mb_fpc_ok && c.waage_ok && c.trinitaer_ok && c.mb9_ok &&
                  c.cluster_ok && c.t9_ok && c.snapshot_ok && c.pipeline_ok && c.nesting_ok);
    return c;
}

