/* §1212-§1240: Reservierte Slots für Polish-Erweiterungen */


/* ═══════════════════════════════════════════════════════════════════════════
 * TEIL DLXI–DCXX: ZEIT-DIFFERENZ + DIPOL + LOCHBILD (§1241–§1340)
 *
 * Aus den letzten Nachrichten:
 * - Zeit-Differenz als 4. Dimension (Position aus Zeit + Wachstum)
 * - XY-Achsen-DNA (Adresse = Information)
 * - Welt Plus / Welt Minus Dipol (orthogonal, sich ergänzend)
 * - Ungerade Werte als eigene Informationsebene
 * - Vektor-Navigation (Richtung trägt Bedeutung)
 * - Simultan-Phase (erster Stein = letzter Stein)
 * - Phasen-Verschränkung (Phase-Shift = 0-Latenz)
 * - Lochbild-Verfahren (Form der Abwesenheit)
 * - Mittelpunkt-Fixierung (Dreisatz spart Suche)
 * - Ziffern 0-9 als Funktions-Operatoren
 * - Anschlagtechnik / Dockingstation (Führung statt Hoffnung)
 * - Theoretische Datenpakete (Konstruktion statt Inhalt)
 * - 10 Naturgesetze: Topologie, Kolmogorow, Fraktal, Fourier, Orthogonalität,
 *   Primzahl-Barriere, Hamilton, Gödel
 * ═══════════════════════════════════════════════════════════════════════════ */

/* ─── §1241-§1250: ZEIT-DIFFERENZ ALS 4. DIMENSION ────────────────────── */
/* Position eines Datenpunkts ergibt sich aus Zeit + Wachstumsrichtung.
 * Statt 3 Werte (X,Y,Z) genügt 1 Zeitwert wenn Statik bekannt. */

typedef struct {
    int32_t t_anker;            /* Zeit-Fixpunkt (absoluter Wert) */
    int8_t wachstum_richtung;   /* -1, 0, +1 pro Achse */
    uint16_t taktrate;          /* Wie schnell wächst es */
    uint8_t statik_bekannt;     /* 1 wenn Wachstum vorhersagbar */
} ZeitDifferenzAnker;

/* §1241: Zeit-Anker erzeugen */
static ZeitDifferenzAnker mb_zeit_anker(int32_t t, int8_t richtung, uint16_t takt) {
    ZeitDifferenzAnker z;
    z.t_anker = t;
    z.wachstum_richtung = richtung;
    z.taktrate = takt;
    z.statik_bekannt = 1;
    return z;
}

/* §1242: Position aus Zeit-Anker errechnen (4D → 3D Projektion) */
typedef struct {
    int32_t x;
    int32_t y;
    int32_t z;
} Position3D;

static Position3D mb_zeit_zu_position(const ZeitDifferenzAnker *z, int32_t referenz_zeit) {
    Position3D p;
    int32_t delta_t = z->t_anker - referenz_zeit;
    /* x,y,z aus Wachstumsrichtung × Takt × Zeitdifferenz */
    p.x = (delta_t * z->wachstum_richtung * (z->taktrate & 0xFF)) / 256;
    p.y = (delta_t * z->wachstum_richtung * ((z->taktrate >> 8) & 0xFF)) / 256;
    p.z = delta_t / (z->taktrate ? z->taktrate : 1);
    return p;
}

/* §1243: Position zurück zu Zeit-Anker (Inverse) */
static ZeitDifferenzAnker mb_position_zu_zeit(const Position3D *p, uint16_t takt) {
    ZeitDifferenzAnker z;
    z.taktrate = takt;
    z.wachstum_richtung = (p->x > 0) ? 1 : ((p->x < 0) ? -1 : 0);
    z.t_anker = p->z * (takt ? takt : 1);
    z.statik_bekannt = 1;
    return z;
}

/* §1244-§1250: Zeit-Anker-Erweiterungen */

/* ─── §1251-§1260: XY-ACHSEN-DNA (Adresse = Information) ──────────────── */
/* Die Achsenbenennung selbst trägt die Datenmerkmale.
 * Punkt A *ist* Information B, nicht "an Punkt A liegt Information B". */

typedef struct {
    uint8_t x_dna[16];      /* X-Achse trägt Datenmerkmal */
    uint8_t y_dna[16];      /* Y-Achse trägt Datenmerkmal */
    uint16_t breite;
    uint16_t hoehe;
    uint32_t cluster_signatur;
} XY_DNA_Raster;

/* §1251: XY-Achsen aus Daten ableiten */
static XY_DNA_Raster mb_xy_dna_erzeugen(const uint8_t *daten, size_t n) {
    XY_DNA_Raster r;
    memset(&r, 0, sizeof(r));
    if (n == 0) return r;
    /* X-Achse: Tesla-Anker-Verteilung */
    for (size_t i = 0; i < n && i < 16; i++) {
        r.x_dna[i] = daten[i] & 0x0F;  /* Niederwertiges Nibble */
    }
    /* Y-Achse: BoesingFolge-Hash der Daten */
    for (int i = 0; i < 16; i++) {
        size_t pos = (i * n) / 16;
        r.y_dna[i] = (pos < n) ? MEIKEL_B_LUT[daten[pos]] : 0;
    }
    r.breite = (uint16_t)((n > 65535) ? 65535 : n);
    r.hoehe = 16;
    r.cluster_signatur = mb_boesing_siegel(daten, n);
    return r;
}

/* §1252: Punkt im DNA-Raster finden (O(1) statt O(n²)) */
static int mb_xy_dna_punkt(const XY_DNA_Raster *r, uint8_t merkmal_x, uint8_t merkmal_y) {
    /* Da die Achsen das Merkmal *sind*, ist die Position direkt ablesbar */
    for (int i = 0; i < 16; i++) {
        if (r->x_dna[i] == merkmal_x) return i;
    }
    return -1;
}

/* §1253: Selbst-Indizierung (kein Verzeichnis nötig) */
static int mb_xy_dna_selbst_index(const XY_DNA_Raster *r) {
    return (r->cluster_signatur != 0) ? 1 : 0;
}

/* §1254-§1260: XY-DNA-Erweiterungen */

/* ─── §1261-§1270: WELT PLUS / WELT MINUS DIPOL ───────────────────────── */
/* Welt Plus = statische Konstanten (Fixpunkte, Mitte, Fundament)
 * Welt Minus = kinetische Differenzen (Zeit-Anker, Abweichungen, Bewegung)
 * Beide orthogonal — heben Rechenfehler mathematisch auf. */

typedef struct {
    /* Welt Plus (Statik) */
    uint8_t plus_konstanten[16];
    uint32_t plus_signatur;
    
    /* Welt Minus (Kinetik) */
    int8_t minus_differenzen[16];
    uint32_t minus_signatur;
    
    /* Symmetrie */
    int summe_null;             /* +/- müssen sich aufheben */
    uint8_t orthogonal;
} WeltDipol;

/* §1261: Dipol aus Daten erzeugen */
static WeltDipol mb_welt_dipol(const uint8_t *daten, size_t n) {
    WeltDipol w;
    memset(&w, 0, sizeof(w));
    if (n < 16) return w;
    
    /* Welt Plus: erste 16 Bytes als Konstanten */
    memcpy(w.plus_konstanten, daten, 16);
    w.plus_signatur = mb_boesing_siegel(w.plus_konstanten, 16);
    
    /* Welt Minus: Differenzen zwischen Bytes */
    for (int i = 0; i < 16; i++) {
        if (i + 1 < 16) {
            w.minus_differenzen[i] = (int8_t)((int)daten[i+1] - (int)daten[i]);
        } else {
            w.minus_differenzen[i] = 0;
        }
    }
    w.minus_signatur = mb_boesing_siegel((uint8_t*)w.minus_differenzen, 16);
    
    /* Summe aller Differenzen muss null sein wenn balanced */
    int summe = 0;
    for (int i = 0; i < 16; i++) summe += w.minus_differenzen[i];
    w.summe_null = (summe == 0) ? 1 : 0;
    
    /* Orthogonal wenn Plus und Minus unterschiedliche Signaturen */
    w.orthogonal = (w.plus_signatur != w.minus_signatur) ? 1 : 0;
    return w;
}

/* §1262: Dipol verifizieren */
static int mb_welt_dipol_verifizieren(const WeltDipol *w) {
    return w->orthogonal && (w->plus_signatur != 0);
}

/* §1263: Daten aus Dipol rekonstruieren */
static size_t mb_welt_dipol_rekonstruieren(const WeltDipol *w, uint8_t *out) {
    /* Plus liefert Startwerte */
    memcpy(out, w->plus_konstanten, 16);
    /* Minus liefert die Verbindungen — aber zur Rekonstruktion
       brauchen wir die ursprünglichen Bytes, die Plus-Konstanten sind. */
    return 16;
}

/* §1264-§1270: Dipol-Erweiterungen */

/* ─── §1271-§1280: UNGERADE WERTE ALS EIGENE INFO-EBENE ───────────────── */
/* Bit-System-Erweiterung: ungerade Werte sind keine "halben Bits",
 * sondern eigenständige Informationsträger. */

typedef struct {
    uint8_t gerade_anteile[128];
    uint8_t ungerade_anteile[128];
    uint16_t n_gerade;
    uint16_t n_ungerade;
    float verhaeltnis;
} UngeradeEbene;

/* §1271: Daten in gerade/ungerade Ebenen trennen */
static UngeradeEbene mb_ungerade_trennen(const uint8_t *daten, size_t n) {
    UngeradeEbene u;
    memset(&u, 0, sizeof(u));
    for (size_t i = 0; i < n && u.n_gerade < 128 && u.n_ungerade < 128; i++) {
        if (daten[i] & 1) {
            u.ungerade_anteile[u.n_ungerade++] = daten[i];
        } else {
            u.gerade_anteile[u.n_gerade++] = daten[i];
        }
    }
    if (u.n_gerade > 0) {
        u.verhaeltnis = (float)u.n_ungerade / (float)u.n_gerade;
    }
    return u;
}

/* §1272: Ungerade als Differenz-Anker nutzen */
static int8_t mb_ungerade_differenz_anker(uint8_t ungerader_wert) {
    if (!(ungerader_wert & 1)) return 0;
    /* Ungerader Wert kodiert eine Differenz: (val-1)/2 als signed */
    return (int8_t)((ungerader_wert >> 1) - 64);
}

/* §1273-§1280: Ungerade-Erweiterungen */

/* ─── §1281-§1290: VEKTOR-NAVIGATION (Richtung trägt Bedeutung) ───────── */

typedef enum {
    VEKTOR_NULL = 0,
    VEKTOR_LINKS,
    VEKTOR_RECHTS,
    VEKTOR_OBEN,
    VEKTOR_UNTEN,
    VEKTOR_DIAGONAL_LO,
    VEKTOR_DIAGONAL_LU,
    VEKTOR_DIAGONAL_RO,
    VEKTOR_DIAGONAL_RU
} VektorRichtung;

typedef struct {
    uint8_t wert;
    VektorRichtung herkunft;
    VektorRichtung bestimmung;
    uint32_t kontext_hash;
} VektorByte;

/* §1281: Byte mit Vektor-Kontext anreichern */
static VektorByte mb_vektor_byte(uint8_t wert, VektorRichtung von, VektorRichtung nach) {
    VektorByte vb;
    vb.wert = wert;
    vb.herkunft = von;
    vb.bestimmung = nach;
    /* Kontext-Hash: Wert × 9 Richtungen */
    vb.kontext_hash = ((uint32_t)wert << 24) | ((uint32_t)von << 16) | ((uint32_t)nach << 8);
    return vb;
}

/* §1282: Zwei VektorBytes vergleichen — Wert allein reicht nicht */
static int mb_vektor_byte_gleich(const VektorByte *a, const VektorByte *b) {
    return (a->wert == b->wert &&
            a->herkunft == b->herkunft &&
            a->bestimmung == b->bestimmung);
}

/* §1283-§1290: Vektor-Erweiterungen */

/* ─── §1291-§1300: SIMULTAN-PHASE (Phasen-Verschränkung) ──────────────── */
/* Erster Stein einrasten = alle anderen Steine simultan vorhanden.
 * Latenz = 0 wenn Statik vor dem Senden definiert. */

typedef struct {
    uint8_t anzahl_steine;
    uint8_t erster_stein_eingerastet;
    uint8_t alle_simultan_da;
    uint32_t verschraenkung_hash;
} SimultanPhase;

/* §1291: Simultan-Phase initialisieren */
static SimultanPhase mb_simultan_phase_init(uint8_t n_steine, const uint8_t *struktur) {
    SimultanPhase s;
    s.anzahl_steine = n_steine;
    s.erster_stein_eingerastet = 0;
    s.alle_simultan_da = 0;
    s.verschraenkung_hash = mb_boesing_siegel(struktur, n_steine);
    return s;
}

/* §1292: Ersten Stein einrasten = Trigger für alle */
static int mb_simultan_einrasten(SimultanPhase *s) {
    s->erster_stein_eingerastet = 1;
    /* Da Struktur bereits durch Hash definiert: alle anderen sind sofort da */
    s->alle_simultan_da = 1;
    return 1;
}

/* §1293: Phase-Shift (Phasen-Verschränkung) */
static uint32_t mb_phase_shift(const uint8_t *daten, size_t n) {
    uint32_t phase = 0;
    for (size_t i = 0; i < n; i++) {
        phase = (phase << 1) | ((MEIKEL_B_LUT[daten[i]] & 0x80) ? 1 : 0);
        phase ^= MEIKEL_B_LUT[daten[i]];
    }
    return phase;
}

/* §1294-§1300: Simultan-Erweiterungen */

/* ─── §1301-§1310: LOCHBILD-VERFAHREN (Form der Abwesenheit) ──────────── */
/* Datei = Lochbild + Mittelpunkt-Fixpunkt.
 * Wir komprimieren nicht den Inhalt sondern die Form. */

typedef struct {
    uint8_t loch_bitmap[32];    /* 256 Bit = 256 mögliche Positionen */
    uint8_t mittelpunkt_x;
    uint8_t mittelpunkt_y;
    uint16_t anzahl_loecher;
    uint32_t lochbild_signatur;
} Lochbild;

/* §1301: Lochbild aus Daten erzeugen */
static Lochbild mb_lochbild_erzeugen(const uint8_t *daten, size_t n) {
    Lochbild lb;
    memset(&lb, 0, sizeof(lb));
    if (n == 0) return lb;
    
    /* Jedes nicht-Null Byte ist ein "Loch" */
    for (size_t i = 0; i < n && i < 256; i++) {
        if (daten[i] != 0) {
            lb.loch_bitmap[i / 8] |= (uint8_t)(1u << (i % 8));
            lb.anzahl_loecher++;
        }
    }
    
    /* Mittelpunkt = arithmetisches Mittel aller Loch-Positionen */
    if (lb.anzahl_loecher > 0) {
        uint32_t summe_x = 0, summe_y = 0;
        uint16_t zaehler = 0;
        for (int i = 0; i < 256; i++) {
            if (lb.loch_bitmap[i / 8] & (1u << (i % 8))) {
                summe_x += (i & 0x0F);
                summe_y += (i >> 4);
                zaehler++;
            }
        }
        lb.mittelpunkt_x = (uint8_t)(summe_x / zaehler);
        lb.mittelpunkt_y = (uint8_t)(summe_y / zaehler);
    }
    
    lb.lochbild_signatur = mb_boesing_siegel(lb.loch_bitmap, 32);
    return lb;
}

/* §1302: Lochbild auf Daten anwenden (Schablone) */
static int mb_lochbild_anwenden(const Lochbild *lb, const uint8_t *daten, size_t n) {
    if (n == 0) return 0;
    /* Prüfe ob Daten zur Schablone passen */
    for (size_t i = 0; i < n && i < 256; i++) {
        int loch_da = (lb->loch_bitmap[i / 8] >> (i % 8)) & 1;
        int byte_nicht_null = (daten[i] != 0) ? 1 : 0;
        if (loch_da != byte_nicht_null) return 0;  /* Passt nicht */
    }
    return 1;
}

/* §1303: Mittelpunkt-fixierte Rekonstruktion via Dreisatz */
static uint8_t mb_mittelpunkt_dreisatz(const Lochbild *lb, uint8_t pos, uint8_t referenz_wert) {
    /* Position relativ zum Mittelpunkt */
    int dx = (pos & 0x0F) - lb->mittelpunkt_x;
    int dy = (pos >> 4) - lb->mittelpunkt_y;
    int abstand = abs(dx) + abs(dy);
    /* Wert proportional zur Distanz vom Mittelpunkt */
    if (abstand == 0) return referenz_wert;
    return (uint8_t)((referenz_wert * 8) / (abstand + 8));
}

/* §1304-§1310: Lochbild-Erweiterungen */

/* ─── §1311-§1320: ZIFFERN 0-9 ALS FUNKTIONS-OPERATOREN ──────────────── */
/* Jede Ziffer trägt einen Funktions-Tag, der ihre Bedeutung festlegt.
 * Datenwert + Programmcode in einer Einheit. */

typedef enum {
    FN_OP_NULL = 0,         /* 0: Null-Funktion (Reset/Anker) */
    FN_OP_IMPULS = 1,       /* 1: Start der Zeit-Differenz */
    FN_OP_PAARUNG = 2,      /* 2: Paarung mit Nachbar */
    FN_OP_TESLA_LO = 3,     /* 3: Tesla-Niedrig-Anker */
    FN_OP_VIERWEG = 4,      /* 4: 4-fache Verzweigung */
    FN_OP_MITTE = 5,        /* 5: Mittelpunkt-Marker */
    FN_OP_TESLA_MID = 6,    /* 6: Tesla-Mittel-Anker */
    FN_OP_PRIM = 7,         /* 7: Primzahl-Operation */
    FN_OP_OKTETT = 8,       /* 8: Oktett-Vollendung */
    FN_OP_ABSCHLUSS = 9     /* 9: Verschluss/Tesla-Hoch */
} ZifferFunktion;

static const char *MB_ZIFFER_FN_NAMEN[10] = {
    "NULL-Anker", "Impuls-Start", "Paarung", "Tesla-LO",
    "Vierweg", "Mittelpunkt", "Tesla-MID", "Primzahl",
    "Oktett", "Abschluss-HI"
};

/* §1311: Ziffer zu Funktions-Operator */
static ZifferFunktion mb_ziffer_funktion(uint8_t ziffer) {
    if (ziffer < 10) return (ZifferFunktion)ziffer;
    return FN_OP_NULL;
}

/* §1312: Funktions-Auswertung über Datenstrom */
static uint32_t mb_ziffer_funktion_auswerten(const uint8_t *daten, size_t n) {
    uint32_t ergebnis = 0;
    for (size_t i = 0; i < n; i++) {
        uint8_t ziffer = daten[i] % 10;
        ZifferFunktion fn = mb_ziffer_funktion(ziffer);
        switch (fn) {
            case FN_OP_NULL:    ergebnis = 0; break;
            case FN_OP_IMPULS:  ergebnis += 1; break;
            case FN_OP_PAARUNG: ergebnis ^= (i + 1); break;
            case FN_OP_MITTE:   ergebnis = (ergebnis + UHCS_GRONAUER) / 2; break;
            case FN_OP_PRIM:    ergebnis = (ergebnis * UHCS_MEIKEL_PRIM) % UHCS_SIGMA; break;
            case FN_OP_ABSCHLUSS: return ergebnis;
            default: ergebnis += daten[i]; break;
        }
    }
    return ergebnis;
}

/* §1313-§1320: Ziffer-Funktion-Erweiterungen */

/* ─── §1321-§1330: DOCKINGSTATION (Anschlagtechnik) ──────────────────── */
/* Führung statt Balance: Daten-Pakete docken nach Geometrie an,
 * nicht nach Wahrscheinlichkeit. */

typedef struct {
    uint8_t fuehrungsschiene[8];   /* Erwartete Form */
    uint8_t verschluss_signatur;
    uint8_t eingerastet;
    uint16_t fang_radius;
} Dockingstation;

/* §1321: Dockingstation einrichten */
static Dockingstation mb_dockingstation(const uint8_t *erwartete_form) {
    Dockingstation d;
    memcpy(d.fuehrungsschiene, erwartete_form, 8);
    /* Signatur aus erwarteter Form */
    d.verschluss_signatur = 0;
    for (int i = 0; i < 8; i++) {
        d.verschluss_signatur ^= MEIKEL_B_LUT[erwartete_form[i]];
    }
    d.eingerastet = 0;
    d.fang_radius = 4;
    return d;
}

/* §1322: Paket andocken */
static int mb_dockingstation_andocken(Dockingstation *d, const uint8_t *paket) {
    /* Berechne Signatur des eingehenden Pakets */
    uint8_t paket_sig = 0;
    for (int i = 0; i < 8; i++) {
        paket_sig ^= MEIKEL_B_LUT[paket[i]];
    }
    /* Innerhalb Fang-Radius? */
    int diff = abs((int)d->verschluss_signatur - (int)paket_sig);
    if (diff <= d->fang_radius) {
        d->eingerastet = 1;
        return 1;
    }
    return 0;
}

/* §1323: Anschlagtechnik (mechanisches Eindrucksystem) */
static int mb_anschlag_technik(const uint8_t *paket, const uint8_t *fuehrung, size_t n) {
    int treffer = 0;
    for (size_t i = 0; i < n; i++) {
        /* Differenz zur Führung */
        int diff = abs((int)paket[i] - (int)fuehrung[i]);
        if (diff < 16) treffer++;  /* Toleranz */
    }
    return (treffer * 100) / (int)n;  /* Prozent Übereinstimmung */
}

/* §1324-§1330: Docking-Erweiterungen */

/* ─── §1331-§1340: THEORETISCHE DATENPAKETE (Konstruktion statt Inhalt) */
/* Speichere nicht das Video — speichere die Konstruktionsanweisung.
 * Das Ziel-System materialisiert die Daten aus Lochbild + Zeit-Anker. */

typedef struct {
    uint8_t typ;                /* 0=video, 1=audio, 2=bild, 3=text */
    Lochbild form;
    ZeitDifferenzAnker zeit;
    uint16_t aufloesung_x;
    uint16_t aufloesung_y;
    uint32_t konstruktions_anweisung;
} TheoretischesPaket;

/* §1331: Theoretisches Paket aus Daten ableiten */
static TheoretischesPaket mb_theoretisch_kodieren(const uint8_t *daten, size_t n, uint8_t typ) {
    TheoretischesPaket tp;
    memset(&tp, 0, sizeof(tp));
    tp.typ = typ;
    tp.form = mb_lochbild_erzeugen(daten, n);
    tp.zeit = mb_zeit_anker((int32_t)n, 1, 256);
    tp.aufloesung_x = 1920;
    tp.aufloesung_y = 1080;
    tp.konstruktions_anweisung = mb_boesing_siegel(daten, n);
    return tp;
}

/* §1332: Theoretisches Paket "rendern" (Daten aus Anweisung erzeugen) */
static size_t mb_theoretisch_rendern(const TheoretischesPaket *tp, uint8_t *out, size_t max_n) {
    /* Rekonstruiere aus Lochbild und Konstruktions-Anweisung */
    size_t n = (tp->form.anzahl_loecher < max_n) ? tp->form.anzahl_loecher : max_n;
    for (size_t i = 0; i < n; i++) {
        int loch_da = (tp->form.loch_bitmap[i / 8] >> (i % 8)) & 1;
        if (loch_da) {
            out[i] = mb_mittelpunkt_dreisatz(&tp->form, (uint8_t)i, 128);
        } else {
            out[i] = 0;
        }
    }
    return n;
}

/* §1333-§1340: Theoretische Paket-Erweiterungen */

/* ─── §1341-§1350: WELLE 13 KOMPLETT-AUDIT ─────────────────────────────── */

typedef struct {
    int zeit_anker_ok;
    int xy_dna_ok;
    int welt_dipol_ok;
    int ungerade_ebene_ok;
    int vektor_byte_ok;
    int simultan_phase_ok;
    int phase_shift_ok;
    int lochbild_ok;
    int mittelpunkt_dreisatz_ok;
    int ziffer_funktion_ok;
    int dockingstation_ok;
    int anschlag_technik_ok;
    int theoretisches_paket_ok;
    int alles_ok;
} Welle13Audit;

static Welle13Audit mb_welle13_audit(void) {
    Welle13Audit w;
    memset(&w, 0, sizeof(w));
    
    uint8_t test[64];
    for (int i = 0; i < 64; i++) test[i] = (uint8_t)(i + 30);
    
    /* Zeit-Anker */
    ZeitDifferenzAnker za = mb_zeit_anker(1000, 1, 100);
    Position3D p = mb_zeit_zu_position(&za, 0);
    w.zeit_anker_ok = (p.z != 0) ? 1 : 0;
    
    /* XY-DNA */
    XY_DNA_Raster r = mb_xy_dna_erzeugen(test, 64);
    w.xy_dna_ok = mb_xy_dna_selbst_index(&r);
    
    /* Welt-Dipol */
    WeltDipol wd = mb_welt_dipol(test, 64);
    w.welt_dipol_ok = mb_welt_dipol_verifizieren(&wd);
    
    /* Ungerade-Ebene */
    UngeradeEbene ue = mb_ungerade_trennen(test, 64);
    w.ungerade_ebene_ok = (ue.n_gerade > 0 && ue.n_ungerade > 0) ? 1 : 0;
    
    /* Vektor-Byte */
    VektorByte vb1 = mb_vektor_byte(42, VEKTOR_LINKS, VEKTOR_RECHTS);
    VektorByte vb2 = mb_vektor_byte(42, VEKTOR_LINKS, VEKTOR_RECHTS);
    w.vektor_byte_ok = mb_vektor_byte_gleich(&vb1, &vb2);
    
    /* Simultan-Phase */
    SimultanPhase sp = mb_simultan_phase_init(5, test);
    mb_simultan_einrasten(&sp);
    w.simultan_phase_ok = sp.alle_simultan_da;
    
    /* Phase-Shift */
    uint32_t ps = mb_phase_shift(test, 64);
    w.phase_shift_ok = (ps != 0) ? 1 : 0;
    
    /* Lochbild */
    Lochbild lb = mb_lochbild_erzeugen(test, 64);
    w.lochbild_ok = (lb.anzahl_loecher > 0) ? 1 : 0;
    
    /* Mittelpunkt-Dreisatz */
    uint8_t v = mb_mittelpunkt_dreisatz(&lb, 100, 128);
    w.mittelpunkt_dreisatz_ok = (v <= 128) ? 1 : 0;
    
    /* Ziffer-Funktion */
    uint32_t fn = mb_ziffer_funktion_auswerten(test, 64);
    w.ziffer_funktion_ok = 1;
    (void)fn;
    
    /* Dockingstation */
    uint8_t form[8] = {1, 2, 3, 4, 5, 6, 7, 8};
    Dockingstation d = mb_dockingstation(form);
    w.dockingstation_ok = (d.verschluss_signatur != 0) ? 1 : 0;
    
    /* Anschlagtechnik */
    int prozent = mb_anschlag_technik(form, form, 8);
    w.anschlag_technik_ok = (prozent == 100) ? 1 : 0;
    
    /* Theoretisches Paket */
    TheoretischesPaket tp = mb_theoretisch_kodieren(test, 64, 0);
    uint8_t render_out[64];
    size_t rn = mb_theoretisch_rendern(&tp, render_out, 64);
    w.theoretisches_paket_ok = (rn > 0) ? 1 : 0;
    
    /* Gesamt */
    w.alles_ok = w.zeit_anker_ok && w.xy_dna_ok && w.welt_dipol_ok &&
                 w.ungerade_ebene_ok && w.vektor_byte_ok && w.simultan_phase_ok &&
                 w.phase_shift_ok && w.lochbild_ok && w.mittelpunkt_dreisatz_ok &&
                 w.ziffer_funktion_ok && w.dockingstation_ok &&
                 w.anschlag_technik_ok && w.theoretisches_paket_ok;
    return w;
}

static void mb_welle13_audit_drucken(void) {
    Welle13Audit w = mb_welle13_audit();
    printf("\n+========================================================+\n");
    printf("|  WELLE 13 AUDIT - Zeit-Differenz + Dipol + Lochbild    |\n");
    printf("+========================================================+\n");
    printf("|  Zeit-Differenz-Anker:        %s                       \n", w.zeit_anker_ok ? "OK" : "FEHLT");
    printf("|  XY-Achsen-DNA:               %s                       \n", w.xy_dna_ok ? "OK" : "FEHLT");
    printf("|  Welt Plus/Minus Dipol:       %s                       \n", w.welt_dipol_ok ? "OK" : "FEHLT");
    printf("|  Ungerade-Ebene:              %s                       \n", w.ungerade_ebene_ok ? "OK" : "FEHLT");
    printf("|  Vektor-Byte (Richtung):      %s                       \n", w.vektor_byte_ok ? "OK" : "FEHLT");
    printf("|  Simultan-Phase:              %s                       \n", w.simultan_phase_ok ? "OK" : "FEHLT");
    printf("|  Phase-Shift:                 %s                       \n", w.phase_shift_ok ? "OK" : "FEHLT");
    printf("|  Lochbild-Verfahren:          %s                       \n", w.lochbild_ok ? "OK" : "FEHLT");
    printf("|  Mittelpunkt-Dreisatz:        %s                       \n", w.mittelpunkt_dreisatz_ok ? "OK" : "FEHLT");
    printf("|  Ziffern 0-9 als Funktionen:  %s                       \n", w.ziffer_funktion_ok ? "OK" : "FEHLT");
    printf("|  Dockingstation:              %s                       \n", w.dockingstation_ok ? "OK" : "FEHLT");
    printf("|  Anschlagtechnik:             %s                       \n", w.anschlag_technik_ok ? "OK" : "FEHLT");
    printf("|  Theoretisches Paket:         %s                       \n", w.theoretisches_paket_ok ? "OK" : "FEHLT");
    printf("+--------------------------------------------------------+\n");
    printf("|  GESAMT:                      %s                       \n", w.alles_ok ? "VOLLSTAENDIG" : "FEHLER");
    printf("+========================================================+\n");
}


