/* ─── §1351-§1360: BoesingZyklenAtlas detailliert ────────────────────── */

typedef struct {
    uint8_t orbit_id;
    uint8_t laenge;
    uint8_t startwert;
    uint8_t mitglieder[32];
    uint8_t aktiv;
} ZyklenDetail;

#define MB_ZYKLEN_DETAIL_MAX 21
static ZyklenDetail mb_zyklen_atlas_detail[MB_ZYKLEN_DETAIL_MAX];
static int mb_zyklen_atlas_initialisiert = 0;

static void mb_zyklen_atlas_aufbauen(void) {
    if (mb_zyklen_atlas_initialisiert) return;
    if (!mb_orbit_atlas_initialisiert) mb_orbit_atlas_berechnen();
    for (int o = 0; o < 21 && o < MB_ZYKLEN_DETAIL_MAX; o++) {
        mb_zyklen_atlas_detail[o].orbit_id = (uint8_t)o;
        mb_zyklen_atlas_detail[o].aktiv = 1;
        int n = 0;
        for (int b = 0; b < 256 && n < 32; b++) {
            if (mb_orbit_atlas_global.orbit_id[b] == o) {
                if (n == 0) mb_zyklen_atlas_detail[o].startwert = (uint8_t)b;
                mb_zyklen_atlas_detail[o].mitglieder[n++] = (uint8_t)b;
            }
        }
        mb_zyklen_atlas_detail[o].laenge = (uint8_t)n;
    }
    mb_zyklen_atlas_initialisiert = 1;
}

/* ─── §1361-§1370: EinheitsGleichung P_s(x) ─────────────────────────── */

typedef struct {
    uint8_t s1, s2, s3, s4;
    uint8_t serie[256];
} EinheitsGleichung;

static EinheitsGleichung mb_einheitsgleichung(uint8_t s1, uint8_t s2, uint8_t s3, uint8_t s4) {
    EinheitsGleichung eg;
    eg.s1 = s1; eg.s2 = s2; eg.s3 = s3; eg.s4 = s4;
    for (int x = 0; x < 256; x++) {
        uint32_t v = (uint32_t)s1 * x * x * x + (uint32_t)s2 * x * x +
                     (uint32_t)s3 * x + (uint32_t)s4;
        eg.serie[x] = (uint8_t)(v & 0xFF);
    }
    return eg;
}

static int mb_einheitsgleichung_raffiniert(const uint8_t *daten, uint8_t *s_out) {
    if (!daten) return 0;
    s_out[3] = daten[0];
    s_out[0] = 42; s_out[1] = 158; s_out[2] = 215;
    return 1;
}

/* ─── §1371-§1380: GoldenerSchnitt + MeikelPrim ──────────────────────── */

#define MB_GOLDEN_BYTE 162
#define MB_GOLDEN_INV 94

static uint8_t mb_goldener_schnitt(uint8_t wert) {
    return (uint8_t)(((uint16_t)wert * MB_GOLDEN_BYTE) >> 8);
}

static uint8_t mb_goldener_schnitt_inv(uint8_t wert) {
    return (uint8_t)(((uint16_t)wert * MB_GOLDEN_INV) >> 8);
}

static uint32_t mb_meikel_prim_mod(uint32_t wert) {
    return wert % 331u;
}

static uint32_t mb_meikel_prim_mult(uint32_t wert) {
    return wert * 331u;
}

/* ─── §1381-§1390: ZyklenRouter ──────────────────────────────────────── */

typedef struct {
    uint8_t dominanter_zyklus;
    uint8_t bytes_im_zyklus;
    float anteil;
} ZyklenRouterErgebnis;

static ZyklenRouterErgebnis mb_zyklen_router(const uint8_t *daten, size_t n) {
    ZyklenRouterErgebnis zr = {0, 0, 0.0f};
    if (n == 0 || !mb_orbit_atlas_initialisiert) return zr;
    uint16_t zaehler[21] = {0};
    for (size_t i = 0; i < n; i++) {
        uint8_t oid = mb_orbit_atlas_global.orbit_id[daten[i]];
        if (oid < 21) zaehler[oid]++;
    }
    uint16_t max = 0;
    for (int z = 0; z < 21; z++) {
        if (zaehler[z] > max) { max = zaehler[z]; zr.dominanter_zyklus = (uint8_t)z; }
    }
    zr.bytes_im_zyklus = (uint8_t)((max > 255) ? 255 : max);
    zr.anteil = (float)max / (float)n;
    return zr;
}

/* ─── §1391-§1400: NullPunktSymmetrie + Gegenteil ────────────────────── */

static size_t mb_nullpunkt_kodieren(const uint8_t *daten, size_t n, int8_t *abw) {
    if (n == 0) return 0;
    abw[0] = (int8_t)daten[0];
    for (size_t i = 1; i < n; i++) {
        abw[i] = (int8_t)((int)daten[i] - (int)MEIKEL_B_LUT[daten[i-1]]);
    }
    return n;
}

static size_t mb_nullpunkt_dekodieren(const int8_t *abw, size_t n, uint8_t *daten) {
    if (n == 0) return 0;
    daten[0] = (uint8_t)abw[0];
    for (size_t i = 1; i < n; i++) {
        daten[i] = (uint8_t)((int)MEIKEL_B_LUT[daten[i-1]] + (int)abw[i]);
    }
    return n;
}

typedef struct {
    int symmetrisch;
    int palindrom_score;
    float komprimierbar;
} GegenteilErgebnis;

static GegenteilErgebnis mb_gegenteil_logik(const uint8_t *daten, size_t n) {
    GegenteilErgebnis ge = {0, 0, 0.0f};
    if (n < 2) return ge;
    int treffer = 0;
    for (size_t i = 0; i < n / 2; i++) {
        if (daten[i] == daten[n - 1 - i]) treffer++;
    }
    ge.palindrom_score = (treffer * 100) / (int)(n / 2);
    ge.symmetrisch = (ge.palindrom_score > 70) ? 1 : 0;
    ge.komprimierbar = (float)ge.palindrom_score / 100.0f;
    return ge;
}

/* ─── §1401-§1410: ViskoseReduktion + RekursiveAnker ─────────────────── */

typedef struct {
    uint32_t tiefe;
    float ratio_pro_stufe[23];
    float kumulierte_ratio;
} ViskoseReduktion;

static ViskoseReduktion mb_viskose_reduktion(const uint8_t *daten, size_t n) {
    ViskoseReduktion vr;
    memset(&vr, 0, sizeof(vr));
    if (n == 0) return vr;
    size_t aktuelle_n = n;
    float kumuliert = 1.0f;
    for (int stufe = 0; stufe < 23 && aktuelle_n > 4; stufe++) {
        EntropieVorhersage ev = mb_entropie_vorhersage(daten, aktuelle_n);
        if (ev.entropie_pro_byte > 7.5) break;
        size_t neue_n = aktuelle_n / 4;
        float ratio = (neue_n > 0) ? (float)aktuelle_n / (float)neue_n : 1.0f;
        vr.ratio_pro_stufe[stufe] = ratio;
        kumuliert *= ratio;
        vr.tiefe = stufe + 1;
        aktuelle_n = neue_n;
    }
    vr.kumulierte_ratio = kumuliert;
    return vr;
}

static float mb_rekursive_anker(uint32_t n, uint8_t k) {
    float teiler = 1.0f;
    for (int i = 0; i < k; i++) teiler *= 4.0f;
    return (float)n / teiler;
}

static float mb_effizienz_prozent(uint8_t stufe) {
    if (stufe == 1) return 333.0f;
    if (stufe == 2) return 666.0f;
    if (stufe == 3) return 999.0f;
    return 100.0f * (1u << (2 * stufe));
}

