/* ─── §1501-§1510: LOCHBILD-SCHLOSS (Stellung statt Passwort) ────────── */

typedef struct {
    uint8_t bitmap[32];
    uint8_t mittelpunkt_x;
    uint8_t mittelpunkt_y;
    uint32_t orts_hash;
    uint64_t zeitfenster_anfang;
    uint64_t zeitfenster_ende;
} LochbildSchloss;

static LochbildSchloss mb_lochbild_schloss_erzeugen(const uint8_t *stellung, size_t n,
                                                     uint64_t zeit_anfang, uint64_t zeit_ende) {
    LochbildSchloss ls;
    memset(&ls, 0, sizeof(ls));
    for (size_t i = 0; i < n && i < 256; i++) {
        if (stellung[i] != 0) {
            ls.bitmap[i / 8] |= (uint8_t)(1u << (i % 8));
        }
    }
    /* Orts-Hash: Hash auf das Fenster, nicht den Inhalt */
    ls.orts_hash = mb_boesing_siegel(ls.bitmap, 32);
    ls.zeitfenster_anfang = zeit_anfang;
    ls.zeitfenster_ende = zeit_ende;
    return ls;
}

static int mb_lochbild_schloss_oeffnen(const LochbildSchloss *ls, const uint8_t *versuch,
                                        size_t n, uint64_t aktuelle_zeit) {
    /* Zeitfenster prüfen */
    if (aktuelle_zeit < ls->zeitfenster_anfang || aktuelle_zeit > ls->zeitfenster_ende) return 0;
    /* Stellung muss zur Bitmap passen */
    for (size_t i = 0; i < n && i < 256; i++) {
        int loch_da = (ls->bitmap[i / 8] >> (i % 8)) & 1;
        int byte_aktiv = (versuch[i] != 0) ? 1 : 0;
        if (loch_da != byte_aktiv) return 0;
    }
    return 1;
}

/* ─── §1511-§1520: BEDEUTUNGSTAUSCH (Symbol-Camouflage) ──────────────── */

typedef struct {
    uint8_t permutation[10];   /* Vertauschung der Ziffern 0-9 */
    uint8_t inverse[10];
    uint32_t signatur;
} Bedeutungstausch;

static Bedeutungstausch mb_bedeutungstausch_erzeugen(uint32_t seed) {
    Bedeutungstausch bt;
    /* Pseudo-zufällige Permutation aus Seed */
    for (int i = 0; i < 10; i++) bt.permutation[i] = (uint8_t)i;
    /* Fisher-Yates basierend auf BoesingFolge */
    for (int i = 9; i > 0; i--) {
        uint8_t j = (uint8_t)((MEIKEL_B_LUT[(seed + i) & 0xFF]) % (i + 1));
        uint8_t tmp = bt.permutation[i];
        bt.permutation[i] = bt.permutation[j];
        bt.permutation[j] = tmp;
    }
    /* Inverse */
    for (int i = 0; i < 10; i++) bt.inverse[bt.permutation[i]] = (uint8_t)i;
    /* Signatur */
    bt.signatur = mb_boesing_siegel(bt.permutation, 10);
    return bt;
}

static uint8_t mb_bedeutungstausch_anwenden(const Bedeutungstausch *bt, uint8_t ziffer) {
    return (ziffer < 10) ? bt->permutation[ziffer] : ziffer;
}

static uint8_t mb_bedeutungstausch_zurueck(const Bedeutungstausch *bt, uint8_t ziffer) {
    return (ziffer < 10) ? bt->inverse[ziffer] : ziffer;
}

/* ─── §1521-§1530: BITCOIN-SPIEGELUNG ────────────────────────────────── */

typedef struct {
    uint8_t bitcoin_id[32];           /* Original-Hash */
    uint8_t spiegel_id[32];            /* Halbierte Spiegelung */
    uint64_t wert_satoshi;
    uint8_t halbiert;
    uint32_t inhaber_signatur;
} BitcoinSpiegel;

static BitcoinSpiegel mb_bitcoin_spiegeln(const uint8_t *original_id, uint64_t satoshi,
                                           uint32_t inhaber) {
    BitcoinSpiegel bs;
    memcpy(bs.bitcoin_id, original_id, 32);
    /* Spiegel = BoesingFolge-Transform der ID */
    for (int i = 0; i < 32; i++) {
        bs.spiegel_id[i] = MEIKEL_B_LUT[original_id[i]];
    }
    bs.wert_satoshi = satoshi;
    bs.halbiert = 0;
    bs.inhaber_signatur = inhaber;
    return bs;
}

static int mb_bitcoin_halbieren(BitcoinSpiegel *bs) {
    /* Erste Hälfte XOR mit zweiter Hälfte = Fragmentierung */
    for (int i = 0; i < 16; i++) {
        bs->spiegel_id[i] ^= bs->spiegel_id[i + 16];
    }
    bs->halbiert = 1;
    return 1;
}

static int mb_bitcoin_zusammenfuehren(BitcoinSpiegel *bs, uint32_t inhaber_pruefung) {
    if (bs->inhaber_signatur != inhaber_pruefung) return 0;
    if (!bs->halbiert) return 1;
    for (int i = 0; i < 16; i++) {
        bs->spiegel_id[i] ^= bs->spiegel_id[i + 16];
    }
    bs->halbiert = 0;
    return 1;
}

