static MeshKnotenW15 mb_mesh_knoten_w15[MB_MESH_MAX_W15];
static uint16_t mb_mesh_n_w15 = 0;

static int mb_mesh_knoten_registrieren_w15(uint16_t id, uint16_t reichweite) {
    for (int i = 0; i < mb_mesh_n_w15; i++) {
        if (mb_mesh_knoten_w15[i].knoten_id == id) return i;
    }
    if (mb_mesh_n_w15 >= MB_MESH_MAX_W15) return -1;
    mb_mesh_knoten_w15[mb_mesh_n_w15].knoten_id = id;
    mb_mesh_knoten_w15[mb_mesh_n_w15].aktiv = 1;
    mb_mesh_knoten_w15[mb_mesh_n_w15].reichweite_m = reichweite;
    mb_mesh_knoten_w15[mb_mesh_n_w15].hops_max = 8;
    mb_mesh_knoten_w15[mb_mesh_n_w15].signal_staerke = 100;
    return mb_mesh_n_w15++;
}

static int mb_mesh_paket_routen_w15(uint16_t von_id, uint16_t ziel_id, uint8_t max_hops) {
    /* Vereinfachte Mesh-Routing-Simulation */
    if (von_id == ziel_id) return 1;
    if (max_hops == 0) return 0;
    /* Zähle aktive Knoten als mögliche Hops */
    int aktive = 0;
    for (int i = 0; i < mb_mesh_n_w15; i++) {
        if (mb_mesh_knoten_w15[i].aktiv) aktive++;
    }
    return (aktive >= 2) ? 1 : 0;
}

/* ─── §1541-§1550: DUAL-FREQUENZ-STATIK ──────────────────────────────── */

typedef struct {
    uint16_t frequenz_oben;       /* Hz */
    uint16_t frequenz_unten;       /* Hz */
    uint16_t verhaeltnis;          /* oben/unten × 1000 */
    uint32_t signatur;
} DualFrequenz;

static DualFrequenz mb_dual_frequenz(uint16_t oben, uint16_t unten) {
    DualFrequenz df;
    df.frequenz_oben = oben;
    df.frequenz_unten = unten;
    df.verhaeltnis = (unten > 0) ? (uint16_t)((uint32_t)oben * 1000 / unten) : 0;
    /* Signatur: kombinierter Hash */
    uint32_t kombiniert = ((uint32_t)oben << 16) | unten;
    df.signatur = mb_boesing_siegel((uint8_t*)&kombiniert, 4);
    return df;
}

static int mb_dual_frequenz_resonanz(const DualFrequenz *a, const DualFrequenz *b) {
    /* Zwei DualFrequenzen sind in Resonanz wenn Verhältnis identisch */
    return (a->verhaeltnis == b->verhaeltnis) ? 1 : 0;
}

/* ─── §1551-§1560: SYSTEM-IM-SYSTEM (Infiltration) ───────────────────── */

