/* ─── §1761-§1770: Welt Plus / Welt Minus Summe-Null ─────────────────── */

typedef struct {
    int32_t welt_plus_summe;
    int32_t welt_minus_summe;
    int32_t summe_total;        /* Plus + Minus muss 0 sein bei Balance */
    uint8_t balance_ok;
    uint8_t buchhaltung_geprueft;
} BuchhaltungDipol;

static BuchhaltungDipol mb_buchhaltung_dipol(const uint8_t *daten, size_t n) {
    BuchhaltungDipol bd;
    memset(&bd, 0, sizeof(bd));
    if (n == 0) return bd;
    /* Welt Plus = gerade Bytes als positive Konstanten */
    /* Welt Minus = ungerade Bytes als negative Differenzen */
    for (size_t i = 0; i < n; i++) {
        if (daten[i] & 1) {
            bd.welt_minus_summe -= (int32_t)(daten[i] - 128);  /* Differenz zu Mitte */
        } else {
            bd.welt_plus_summe += (int32_t)(daten[i] - 128);
        }
    }
    bd.summe_total = bd.welt_plus_summe + bd.welt_minus_summe;
    bd.balance_ok = (abs(bd.summe_total) < (int32_t)(n * 8)) ? 1 : 0;
    bd.buchhaltung_geprueft = 1;
    return bd;
}

/* ─── §1771-§1780: Ziffer-Operatoren selbstausführend ─────────────────── */
/* Jede Ziffer 0-9 trägt ihren eigenen Funktions-Tag inline mit */

typedef struct {
    uint8_t ziffer;             /* 0-9 */
    uint8_t funktions_tag;      /* Inline-Befehl */
    uint8_t hinweis_merkmal;    /* Macht Ziffer "intelligent" */
    uint16_t logischer_sprung_ziel;
} ZifferSelbstausfuehrend;

static ZifferSelbstausfuehrend mb_ziffer_selbstausfuehrend(uint8_t ziffer) {
    ZifferSelbstausfuehrend zs;
    zs.ziffer = ziffer % 10;
    zs.funktions_tag = zs.ziffer;  /* Ziffer = ihre eigene Funktion */
    /* Hinweis-Merkmal: zeigt nächsten logischen Sprung an */
    zs.hinweis_merkmal = MEIKEL_B_LUT[zs.ziffer];
    /* Logischer Sprung: Ziel der Ziffer im Cluster */
    zs.logischer_sprung_ziel = (uint16_t)((uint32_t)zs.ziffer * UHCS_MEIKEL_PRIM) % 1000;
    return zs;
}

static uint32_t mb_ziffer_kette_ausfuehren(const uint8_t *kette, size_t n) {
    /* Ziffern als Operatoren ausführen, jede Ziffer ist Befehl */
    uint32_t akku = 0;
    for (size_t i = 0; i < n; i++) {
        ZifferSelbstausfuehrend zs = mb_ziffer_selbstausfuehrend(kette[i]);
        switch (zs.funktions_tag) {
            case 0: akku = 0; break;                             /* NULL-Anker */
            case 1: akku += zs.hinweis_merkmal; break;           /* Impuls */
            case 2: akku ^= zs.logischer_sprung_ziel; break;     /* Paarung */
            case 3: case 6: case 9: akku <<= 1; break;           /* Tesla */
            case 4: akku >>= 1; break;                            /* Vierweg */
            case 5: akku = (akku + UHCS_GRONAUER) / 2; break;    /* Mittelpunkt */
            case 7: akku = (akku * UHCS_MEIKEL_PRIM) % UHCS_SIGMA; break;  /* Prim */
            case 8: akku |= zs.hinweis_merkmal; break;           /* Oktett */
        }
    }
    return akku;
}

/* ─── §1781-§1790: Strich in der Mitte / Ansetz-Prinzip ──────────────── */

typedef struct {
    uint8_t strich_position;       /* Nullpunkt im Cluster */
    uint8_t links_haelfte_anteil;
    uint8_t rechts_haelfte_anteil;
    uint8_t fuehrungsschiene_aktiv;
    uint8_t dreifach_pruefung_uebersprungen;
} StrichInDerMitte;

static StrichInDerMitte mb_strich_mitte(const uint8_t *daten, size_t n) {
    StrichInDerMitte sm;
    memset(&sm, 0, sizeof(sm));
    if (n == 0) return sm;
    
    sm.strich_position = (uint8_t)((n / 2) & 0xFF);
    
    /* Anteile beidseitig */
    uint32_t links_summe = 0, rechts_summe = 0;
    for (size_t i = 0; i < n / 2; i++) links_summe += daten[i];
    for (size_t i = n / 2; i < n; i++) rechts_summe += daten[i];
    
    uint32_t total = links_summe + rechts_summe;
    if (total > 0) {
        sm.links_haelfte_anteil = (uint8_t)((links_summe * 100) / total);
        sm.rechts_haelfte_anteil = (uint8_t)((rechts_summe * 100) / total);
    }
    sm.fuehrungsschiene_aktiv = 1;
    sm.dreifach_pruefung_uebersprungen = 1;  /* Standort/Bereich/Zeit eingespart */
    return sm;
}

