/* ─── §1831-§1840: Theoretisches Datenpaket (Konstruktion statt Inhalt) */

typedef struct {
    uint32_t konstruktions_anweisung;
    uint8_t lochbild_signatur[16];
    uint64_t zeit_impuls;
    uint16_t aufloesung_x;
    uint16_t aufloesung_y;
    uint8_t typ;                    /* 0=Bild, 1=Video, 2=Audio, 3=Text */
    uint8_t differenz_fixpunkte;    /* Anzahl Fixpunkte */
    float kompressions_ratio_geschaetzt;
} TheoretischesPaketV2;

static TheoretischesPaketV2 mb_theoretisches_paket_v2(const uint8_t *daten, size_t n, uint8_t typ) {
    TheoretischesPaketV2 tp;
    memset(&tp, 0, sizeof(tp));
    tp.typ = typ;
    tp.konstruktions_anweisung = mb_boesing_siegel(daten, (n > 256) ? 256 : n);
    /* Lochbild: bitmap aus Daten (16 Bytes = 128 Bits) */
    for (size_t i = 0; i < n && i < 128; i++) {
        if (daten[i] != 0) tp.lochbild_signatur[i / 8] |= (uint8_t)(1u << (i % 8));
    }
    tp.zeit_impuls = (uint64_t)n;
    tp.aufloesung_x = 1920;
    tp.aufloesung_y = 1080;
    tp.differenz_fixpunkte = 5;
    /* Geschätzte Ratio: nur Konstruktions-Anweisung gespeichert (24 Bytes total) */
    tp.kompressions_ratio_geschaetzt = (n > 0) ? (float)n / 24.0f : 1.0f;
    return tp;
}

/* ─── §1841-§1850: Krebs-Erkennung (Soll-Lochbild Abweichung) ────────── */

typedef struct {
    uint8_t soll_lochbild[32];      /* Gesundheits-Schablone */
    uint8_t ist_lochbild[32];       /* Aktueller Zustand */
    uint16_t abweichungs_score;     /* 0-256 */
    uint8_t krebs_kandidat;         /* 1 wenn Score > Schwelle */
    uint16_t schwelle;
} KrebsErkennung;

static KrebsErkennung mb_krebs_erkennung(const uint8_t *soll, const uint8_t *ist, size_t n) {
    KrebsErkennung ke;
    memset(&ke, 0, sizeof(ke));
    size_t kopiere = (n > 32) ? 32 : n;
    memcpy(ke.soll_lochbild, soll, kopiere);
    memcpy(ke.ist_lochbild, ist, kopiere);
    /* Hamming-Distanz zwischen beiden Lochbildern */
    for (size_t i = 0; i < kopiere; i++) {
        uint8_t xor_byte = ke.soll_lochbild[i] ^ ke.ist_lochbild[i];
        /* Anzahl gesetzte Bits */
        for (int b = 0; b < 8; b++) {
            if (xor_byte & (1u << b)) ke.abweichungs_score++;
        }
    }
    ke.schwelle = (uint16_t)(kopiere * 8 / 4);  /* 25% Abweichung = Alarm */
    ke.krebs_kandidat = (ke.abweichungs_score > ke.schwelle) ? 1 : 0;
    return ke;
}

