/* Drei Cache-Stufen (Heiss/Warm/Kalt) */
typedef struct {
    uint8_t  heiss_ram_aktiv;        /* Sofort-Zugriff */
    uint8_t  warm_komprimiert_aktiv;  /* Schnell, RAM */
    uint8_t  kalt_disk_aktiv;        /* Archiv, max Kompr */
    uint64_t heiss_groesse_bytes;
    uint64_t warm_groesse_bytes;
    uint64_t kalt_groesse_bytes;
} DreiStufenCache;

static DreiStufenCache mb_drei_stufen_cache(void) {
    DreiStufenCache c;
    c.heiss_ram_aktiv = 1;
    c.warm_komprimiert_aktiv = 1;
    c.kalt_disk_aktiv = 1;
    c.heiss_groesse_bytes = 1ULL * 1024 * 1024 * 64;     /* 64 MB */
    c.warm_groesse_bytes = 1ULL * 1024 * 1024 * 256;     /* 256 MB */
    c.kalt_groesse_bytes = 1ULL * 1024 * 1024 * 1024;    /* 1 GB */
    return c;
}

/* CO2-Berechnung */
typedef struct {
    float  co2_pro_mb_g;             /* Gramm CO2 pro MB */
    uint64_t bytes_processed;
    float  total_co2_g;
    float  energie_kwh;
} CO2Berechnung;

static CO2Berechnung mb_co2_berechnung(uint64_t bytes) {
    CO2Berechnung c;
    c.co2_pro_mb_g = 0.05f;          /* 50 mg CO2 / MB */
    c.bytes_processed = bytes;
    c.total_co2_g = (bytes / 1048576.0f) * c.co2_pro_mb_g;
    c.energie_kwh = c.total_co2_g / 400.0f;  /* ~400g CO2/kWh */
    return c;
}

