    Welle22Audit w = mb_welle22_audit();
    printf("\n+============================================================+\n");
    printf("|  WELLE 22 - REALITAETS-INFORMATIK (Zero-Storage + U0-U9)   |\n");
    printf("+============================================================+\n");
