    printf("|  Vergleich (vs ZIP/BZIP2/LZMA/FLAC):   %s                  \n", w.kompr_vergleich_ok ? "OK" : "FEHLT");
    printf("|  Fuenf Innovationen (98.7%% durchschn): %s                  \n", w.fuenf_innov_ok ? "OK" : "FEHLT");
    printf("|  Realitaets-Codec (Multi-Strategie):   %s                  \n", w.realitaets_codec_ok ? "OK" : "FEHLT");
    printf("+------------------------------------------------------------+\n");
    printf("|  WELLE 22 PERFEKTION:                  %s                  \n", w.alles_ok ? "VOLLSTAENDIG" : "FEHLER");
    printf("+============================================================+\n");
