                uint8_t *orig = (uint8_t *)malloc(n);
                uint8_t *comp = (uint8_t *)malloc(n * 4 + 1024);
                uint8_t *dec = (uint8_t *)malloc(n * 4 + 1024);
                if (!orig || !comp || !dec) { free(orig); free(comp); free(dec); continue; }
                uint32_t st = seeds[si] + (uint32_t)sz;
                for (size_t i = 0; i < n; i++) { st = st * 1103515245 + 12345; orig[i] = (st >> 16) & 0xFF; }
