    /* --- Gruppe 31: Streaming-Block-Kompressor --- */
    printf("--- Gruppe 31: Streaming-Block ---\n");
    {
        /* Test: Stream-Roundtrip mit 128KB Daten (>64KB) */
        selftest_total++;
        {
            size_t big_n = 131072; /* 128KB */
            uint8_t *big_in = (uint8_t *)malloc(big_n);
            uint8_t *big_comp = (uint8_t *)malloc(big_n * 2 + 4096);
            uint8_t *big_out = (uint8_t *)malloc(big_n + 4096);
            if (big_in && big_comp && big_out) {
                for (size_t i = 0; i < big_n; i++) big_in[i] = (uint8_t)(i * 13 + 7);
                size_t comp_sz = 0;
                StreamErgebnis cr = mb_stream_compress(big_in, big_n, big_comp, big_n * 2 + 4096, &comp_sz);
                if (cr.stream_ok && comp_sz > 0) {
                    size_t dec_sz = 0;
                    StreamErgebnis dr = mb_stream_decompress(big_comp, comp_sz, big_out, big_n + 4096, &dec_sz);
                    if (dr.stream_ok && dec_sz == big_n && memcmp(big_in, big_out, big_n) == 0) {
                        selftest_ok_count++;
                        printf("  OK Stream-Roundtrip 128KB (%u Bloecke, %zu->%zu)\n", cr.block_count, big_n, comp_sz);
                    } else { selftest_fail_count++; printf("  FAIL Stream-Decompress\n"); }
                } else { selftest_fail_count++; printf("  FAIL Stream-Compress\n"); }
            } else { selftest_fail_count++; printf("  FAIL Stream-Alloc\n"); }
            free(big_in); free(big_comp); free(big_out);
        }

        /* Test: Stream-Roundtrip mit 200KB Nullen (Kompression pruefbar) */
        selftest_total++;
        {
            size_t big_n = 204800; /* 200KB */
            uint8_t *big_in = (uint8_t *)calloc(big_n, 1);
            uint8_t *big_comp = (uint8_t *)malloc(big_n * 2 + 4096);
            uint8_t *big_out = (uint8_t *)malloc(big_n + 4096);
            if (big_in && big_comp && big_out) {
                size_t comp_sz = 0;
                StreamErgebnis cr = mb_stream_compress(big_in, big_n, big_comp, big_n * 2 + 4096, &comp_sz);
                if (cr.stream_ok && comp_sz > 0 && comp_sz < big_n) {
                    size_t dec_sz = 0;
                    StreamErgebnis dr = mb_stream_decompress(big_comp, comp_sz, big_out, big_n + 4096, &dec_sz);
                    if (dr.stream_ok && dec_sz == big_n && memcmp(big_in, big_out, big_n) == 0) {
                        selftest_ok_count++;
                        printf("  OK Stream-Roundtrip 200KB Nullen (Ratio %.1fx)\n", (double)big_n / (double)comp_sz);
                    } else { selftest_fail_count++; printf("  FAIL Stream-Decompress Nullen\n"); }
                } else { selftest_fail_count++; printf("  FAIL Stream-Compress Nullen (%zu)\n", comp_sz); }
            } else { selftest_fail_count++; printf("  FAIL Stream-Alloc Nullen\n"); }
            free(big_in); free(big_comp); free(big_out);
        }

        /* Test: CRC-Integritaet ueber Stream */
        selftest_total++;
        {
            size_t big_n = 100000;
            uint8_t *big_in = (uint8_t *)malloc(big_n);
            uint8_t *big_comp = (uint8_t *)malloc(big_n * 2 + 4096);
            if (big_in && big_comp) {
                for (size_t i = 0; i < big_n; i++) big_in[i] = (uint8_t)(i ^ (i >> 8));
                size_t comp_sz = 0;
                StreamErgebnis cr = mb_stream_compress(big_in, big_n, big_comp, big_n * 2 + 4096, &comp_sz);
                uint32_t expected_crc = uhcs_crc32(big_in, big_n);
                if (cr.stream_ok && cr.crc_gesamt == expected_crc) {
                    selftest_ok_count++;
                    printf("  OK Stream-CRC=0x%08X (%zu Bytes)\n", cr.crc_gesamt, big_n);
                } else { selftest_fail_count++; printf("  FAIL Stream-CRC\n"); }
            } else { selftest_fail_count++; printf("  FAIL Stream-CRC-Alloc\n"); }
            free(big_in); free(big_comp);
        }
    }

