/* Klang-Lookup: ASCII → Tonwert */
static uint8_t mb_klang_tonwert(uint8_t ch) {
    uint8_t c = ch | 0x20; /* lowercase */
    if (c >= 'a' && c <= 'z') return KLANG_MATRIX[c - 'a'].ton_wert;
    if (ch >= '0' && ch <= '9') return (uint8_t)((ch - '0') * 28); /* Ziffern: 0,28,56,...,252 */
    return 126; /* Sonderzeichen → Gronau-Anker */
}

/* ===== SCHLUSSSTEIN-LOGIK (§36) ===== */
/* SchlusssteinResult typedef: siehe Forward-Declaration oben (vor TEIL XXV) */

static SchlusssteinResult mb_schlussstein(uint8_t stein_a, uint8_t stein_b) {
    SchlusssteinResult r;
    r.stein_a = stein_a;
    r.stein_b = stein_b;

    /* Differenz (immer positiv im Ring mod 256) */
    int diff = (int)stein_b - (int)stein_a;
    if (diff < 0) diff += 256;
    r.differenz = (uint8_t)diff;

    /* Der Schlussstein ist der geometrische Mittelpunkt im Ring */
    r.schlussstein = (uint8_t)((stein_a + diff / 2) % 256);

    /* Eigenbereich: wenn Differenz ein Vielfaches von 6 ist → logisch vordefiniert */
    r.eigenbereich = (diff % 6 == 0 && diff > 0) ? 1 : 0;

    /* Sigma-Validierung: Summe der drei Steine mod 568 */
    uint32_t summe = (uint32_t)stein_a + (uint32_t)r.schlussstein + (uint32_t)stein_b;
    r.sigma_valid = (summe % 568 < 42) ? 1 : 0;  /* Nahe am Sigma-Resonanzpunkt */

    return r;
}

/* ===== AUSSCHLUSS-FILTER (§35: Aphaeresis) ===== */
/* Bestimmt, ob ein Byte-Wert „Zufall" oder „Logik" ist,
 * basierend auf dem umgebenden Anker-Kontext. */
static uint8_t mb_ausschluss_pruefung(uint8_t wert, uint8_t anker_links, uint8_t anker_rechts) {
    /* Der Wert ist „logisch", wenn er die Schlussstein-Bedingung erfüllt */
    SchlusssteinResult sr = mb_schlussstein(anker_links, anker_rechts);
    int diff_zum_schluss = (int)wert - (int)sr.schlussstein;
    if (diff_zum_schluss < 0) diff_zum_schluss = -diff_zum_schluss;

    /* Toleranz: innerhalb der Gronau-Nähe (±6) gilt als logisch */
    return (diff_zum_schluss <= 6) ? 1 : 0;  /* 1=Logik, 0=Zufall */
}

/* ===== RESONANZ-KOHÄRENZ (6er-Statik über Sequenz) ===== */
static uint8_t mb_resonanz_koharenz(const uint8_t *daten, size_t len) {
    if (!daten || len < 2) return 0;

    uint32_t kohaerente_uebergaenge = 0;
    for (size_t i = 1; i < len; i++) {
        int diff = (int)daten[i] - (int)daten[i - 1];
        if (diff < 0) diff = -diff;
        if (diff % 6 == 0) kohaerente_uebergaenge++;
    }

    return (uint8_t)(kohaerente_uebergaenge * 255 / (len - 1));
}

/* ===== QUANTEN-STATIK-PROFIL (§34) ===== */
/* QuantenStatikProfil typedef: siehe Forward-Declaration oben (vor TEIL XXV) */

static QuantenStatikProfil mb_quanten_statik(const uint8_t *daten, size_t len) {
    QuantenStatikProfil qsp;
    memset(&qsp, 0, sizeof(qsp));
    if (!daten || len < 3) return qsp;

    qsp.total_bytes = (uint32_t)len;
    uint32_t logik = 0;

    for (size_t i = 1; i < len - 1; i++) {
        /* Jedes Byte wird gegen seine Nachbarn als Anker geprüft */
        if (mb_ausschluss_pruefung(daten[i], daten[i-1], daten[i+1])) {
            logik++;
        }
    }

    qsp.logik_bytes = logik;
    qsp.zufall_bytes = (uint32_t)(len - 2) - logik;  /* Ränder ausgenommen */
    qsp.eigenbereich_ratio = (len > 2) ? (uint8_t)(logik * 255 / (len - 2)) : 0;
    qsp.destillations_grad = qsp.eigenbereich_ratio;  /* Reinheit = Eigenbereich-Anteil */
    qsp.resonanz_koharenz = mb_resonanz_koharenz(daten, len);

    return qsp;
}

