    printf("║  §144 Ziffern 0-9 lueckenlos:       %s                                ║\n",
           k->formen_09_korrekt ? "0-9 KOMPLETT ✓" : "LUECKE ✗");
    printf("╠══════════════════════════════════════════════════════════════════════════╣\n");
    printf("║  §145 Mathematik (Shannon=8Bit):    %s                                ║\n",
           k->math_perfektion ? "PERFEKT ✓" : "SUBOPTIMAL ✗");
    printf("║  §145 Effizienz (Roundtrip 256/256):%s                                ║\n",
           k->effizienz_optimum ? "OPTIMAL ✓" : "VERLUST ✗");
    printf("║  §145 Logik konsistent:             %s                                ║\n",
           k->logik_konsistent ? "KONSISTENT ✓" : "UNLOGISCH ✗");
    printf("╠══════════════════════════════════════════════════════════════════════════╣\n");
    printf("║  ═══════════════════════════════════════════════════════════════════    ║\n");
    printf("║  PERFEKTION:  Mathematik ✓  Struktur ✓  Effizienz ✓                   ║\n");
