/* ===== BENCHMARK ===== */
static void run_benchmark(void) {
    printf("\nBenchmark laeuft...\n");
    uint8_t original[UHCS_MAX_BLOCK];
    uint8_t compressed[UHCS_MAX_BLOCK * 3];
    uint8_t decompressed[UHCS_MAX_BLOCK];
    const char *names[] = {"Nullen", "Einsen", "Aufsteigend", "Text"};
    for (int t = 0; t < 4; t++) {
        size_t n = 4096;
        memset(original, 0, n);
        if (t == 1) memset(original, 0xFF, n);
        else if (t == 2) for (size_t i = 0; i < n; i++) original[i] = i % 256;
        else if (t == 3) {
            const char *txt = "MB-MEISTERWERK v31.0 - Meikel Boesing Gronau 2026 ";
            size_t l = strlen(txt);
            for (size_t i = 0; i < n; i++) original[i] = txt[i % l];
        }
        struct timespec ts1, ts2;
        clock_gettime(CLOCK_MONOTONIC, &ts1);
        size_t comp_sz = uhcs_compress(original, n, compressed, sizeof(compressed));
        clock_gettime(CLOCK_MONOTONIC, &ts2);
        double compress_ms = ((double)ts2.tv_sec - (double)ts1.tv_sec) * 1000.0 + ((double)ts2.tv_nsec - (double)ts1.tv_nsec) / 1e6;
        if (comp_sz == 0) { printf("%s: Kompression fehlgeschlagen\n", names[t]); continue; }
        clock_gettime(CLOCK_MONOTONIC, &ts1);
        size_t dec_sz = uhcs_decompress(compressed, comp_sz, decompressed, sizeof(decompressed));
        clock_gettime(CLOCK_MONOTONIC, &ts2);
        double decompress_ms = ((double)ts2.tv_sec - (double)ts1.tv_sec) * 1000.0 + ((double)ts2.tv_nsec - (double)ts1.tv_nsec) / 1e6;
        if (dec_sz != n || memcmp(original, decompressed, n) != 0) {
            printf("%s: Roundtrip fehlgeschlagen\n", names[t]);
        } else {
            printf("%s: %zu -> %zu Bytes, Ratio %.2fx, Compress %.2fms, Decompress %.2fms\n",
                   names[t], n, comp_sz, (double)n / (double)comp_sz, compress_ms, decompress_ms);
        }
    }
    printf("Benchmark abgeschlossen.\n");
}

/* ===== AUTARKER ZYKLUS (Linux-direkt, selbsttreibend, fehlersicher) ===== */
static uint32_t mb_autark_next(uint32_t *state, uint8_t feedback) {
    uint32_t x = *state ? *state : 331u;
    x ^= x << 13;
    x ^= x >> 17;
    x ^= x << 5;
    x ^= (uint32_t)feedback * 331u;
    *state = x;
    return x;
}

static int run_autark_zyklus(uint32_t runden, uint32_t seed) {
    const size_t block_size = 4096;
    if (runden == 0 || runden > 10000) {
        fprintf(stderr, "Fehler: --zyklen muss zwischen 1 und 10000 liegen\n");
        return 1;
    }

    uint8_t *eingang = (uint8_t *)malloc(block_size);
    uint8_t *komp = (uint8_t *)malloc(block_size * 4 + 1024);
    uint8_t *ausgang = (uint8_t *)malloc(block_size);
    if (!eingang || !komp || !ausgang) {
        free(eingang); free(komp); free(ausgang);
        fprintf(stderr, "Fehler: Speicherzuweisung fuer Autark-Zyklus fehlgeschlagen\n");
        return 1;
    }

    uint32_t state = seed ? seed : 331u;
    uint8_t feedback = 126;
    double ratio_sum = 0.0;
    uint8_t min_destillation = 255;
    uint8_t min_koharenz = 255;

    printf("\n=== AUTARKER ZYKLUS START (%u Runden, %zu Bytes/Runde) ===\n", runden, block_size);
    for (uint32_t r = 0; r < runden; r++) {
        for (size_t i = 0; i < block_size; i++) {
            uint32_t v = mb_autark_next(&state, (uint8_t)(feedback + (uint8_t)i + (uint8_t)r));
            eingang[i] = (uint8_t)(v & 0xFF);
        }

        size_t komp_sz = uhcs_compress(eingang, block_size, komp, block_size * 4 + 1024);
        if (komp_sz == 0) {
            fprintf(stderr, "Fehler in Runde %u: Kompression fehlgeschlagen\n", r + 1);
            free(eingang); free(komp); free(ausgang);
            return 1;
        }

        size_t ausgang_sz = uhcs_decompress(komp, komp_sz, ausgang, block_size);
        if (ausgang_sz != block_size || memcmp(eingang, ausgang, block_size) != 0) {
            fprintf(stderr, "Fehler in Runde %u: Roundtrip-Validierung fehlgeschlagen\n", r + 1);
            free(eingang); free(komp); free(ausgang);
            return 1;
        }

        QuantenStatikProfil qsp = mb_quanten_statik(eingang, block_size);
        uint32_t digest_in = uhcs_crc32(eingang, block_size);
        uint32_t digest_comp = uhcs_crc32(komp, komp_sz);
        feedback = (uint8_t)((digest_in ^ digest_comp ^ (uint32_t)komp_sz ^ qsp.resonanz_koharenz) & 0xFF);
        state ^= (uint32_t)qsp.destillations_grad + ((uint32_t)qsp.resonanz_koharenz << 8);

        double ratio = (double)block_size / (double)komp_sz;
        ratio_sum += ratio;
        if (qsp.destillations_grad < min_destillation) min_destillation = qsp.destillations_grad;
        if (qsp.resonanz_koharenz < min_koharenz) min_koharenz = qsp.resonanz_koharenz;

        printf("Runde %4u/%u | Ratio %.2fx | Destillation %3u | Kohaerenz %3u\n",
               r + 1, runden, ratio, qsp.destillations_grad, qsp.resonanz_koharenz);
    }

    printf("=== AUTARKER ZYKLUS OK | Avg-Ratio %.2fx | Min-Destillation %u | Min-Kohaerenz %u ===\n",
           ratio_sum / (double)runden, min_destillation, min_koharenz);

    free(eingang); free(komp); free(ausgang);
    return 0;
}

/* ===== DATEI-OPERATIONEN ===== */
static int file_exists(const char *path) {
    return access(path, F_OK) == 0;
}

static size_t read_file(const char *path, uint8_t **data) {
    FILE *f = fopen(path, "rb");
    if (!f) return 0;
    fseek(f, 0, SEEK_END);
    long sz = ftell(f);
    if (sz <= 0) { fclose(f); return 0; }
    fseek(f, 0, SEEK_SET);
    *data = (uint8_t *)malloc((size_t)sz);
    if (!*data) { fclose(f); return 0; }
    size_t rd = fread(*data, 1, (size_t)sz, f);
    fclose(f);
    return rd;
}

static int write_file(const char *path, const uint8_t *data, size_t sz) {
    FILE *f = fopen(path, "wb");
    if (!f) return 0;
    fwrite(data, 1, sz, f);
    fclose(f);
    return 1;
}

