        SK_Kette k = mb_sk_init();
        mb_sk_schritt_hinzu(&k, SK_OP_ADD, 42);       /* +42 (Grundkonstante) */
        mb_sk_schritt_hinzu(&k, SK_OP_LUT, 0);        /* LUT-Transformation */
        mb_sk_schritt_hinzu(&k, SK_MB_OP_BOESING, 0);    /* BoesingFolge */
        mb_sk_schritt_hinzu(&k, SK_OP_XOR, UHCS_GRONAUER);  /* XOR mit Gronauer */
        mb_sk_schritt_hinzu(&k, SK_OP_CRC, 0);        /* CRC-Fixierung */
        mb_sk_schritt_hinzu(&k, SK_OP_INV, 0);        /* Inverse LUT */

        uint8_t ergebnis = mb_sk_ausfuehren(&k, eingabe);
        printf("\nEingabe: %u (0x%02X)\n", eingabe, eingabe);
        mb_sk_print(&k);
        printf("Ergebnis: %u (0x%02X)\n\n", ergebnis, ergebnis);
