/* ═══════════════════════════════════════════════════════════════════════════════
 *  TEIL CXII: Hardware-Waechter / HAL (§248-§250)
 *  - §248 Hardware-Profiling — Systemerkennung
 *  - §249 Dynamische Taktung & Cluster-Priorisierung
 *  - §250 Thermische Ueberwachung & Taktische Deckelung
 *
 *  Der "Kaefig fuer das Monster" — das Taktik-Modul das die Hardware
 *  besetzt statt sie nur zu nutzen. Die 00001-Taktung bekommt hier
 *  ihren geschuetzten Raum.
 * ═══════════════════════════════════════════════════════════════════════════════ */

static HardwareWaechterErgebnis mb_hardware_waechter(void) {
    HardwareWaechterErgebnis r;
    memset(&r, 0, sizeof(r));

    /* §248: Hardware-Profiling — "Auf was fuer einem Eisen laufen wir?" */
    {
        /* CPU-Kerne */
#ifdef _SC_NPROCESSORS_ONLN
        long ncpu = sysconf(_SC_NPROCESSORS_ONLN);
        r.cpu_kerne = (ncpu > 0) ? (uint32_t)ncpu : 1;
#else
        r.cpu_kerne = 1;
#endif

        /* RAM gesamt (aus /proc/meminfo unter Linux) */
        r.ram_total_kb = 0;
        FILE *f = fopen("/proc/meminfo", "r");
        if (f) {
            char line[256];
            while (fgets(line, sizeof(line), f)) {
                unsigned long val = 0;
                if (sscanf(line, "MemTotal: %lu kB", &val) == 1) {
                    r.ram_total_kb = (uint64_t)val;
                    break;
                }
            }
            fclose(f);
        }
        if (r.ram_total_kb == 0) {
#ifdef _SC_PHYS_PAGES
            long pages = sysconf(_SC_PHYS_PAGES);
            long pgsz  = sysconf(_SC_PAGESIZE);
            if (pages > 0 && pgsz > 0) {
                r.ram_total_kb = (uint64_t)pages * (uint64_t)pgsz / 1024;
            }
#endif
        }

        /* Cache-Line-Groesse (Standard: 64 Bytes) */
#ifdef _SC_LEVEL1_DCACHE_LINESIZE
        long cl = sysconf(_SC_LEVEL1_DCACHE_LINESIZE);
        r.cache_line_bytes = (cl > 0) ? (uint32_t)cl : 64;
#else
        r.cache_line_bytes = 64;
#endif

        /* L1/L2 Cache (Schaetzung aus sysconf oder Defaults) */
#ifdef _SC_LEVEL1_DCACHE_SIZE
        long l1 = sysconf(_SC_LEVEL1_DCACHE_SIZE);
        r.l1_cache_kb = (l1 > 0) ? (uint32_t)(l1 / 1024) : 32;
#else
        r.l1_cache_kb = 32;
#endif

#ifdef _SC_LEVEL2_CACHE_SIZE
        long l2 = sysconf(_SC_LEVEL2_CACHE_SIZE);
        r.l2_cache_kb = (l2 > 0) ? (uint32_t)(l2 / 1024) : 256;
#else
        r.l2_cache_kb = 256;
#endif

        /* Page Size */
        long ps = sysconf(_SC_PAGESIZE);
        r.page_size = (ps > 0) ? (uint32_t)ps : 4096;
    }

    /* §249: Dynamische Taktung & Cluster-Priorisierung
     * "Du besetzt die Hardware, statt sie nur zu nutzen."
     * Berechne optimale Blockgroesse und pruefe ob 256er-Netz in Cache passt. */
    {
        /* Optimale Blockgroesse: Cache-Line-aligned, maximal L1-freundlich */
        r.optimale_blockgroesse = r.cache_line_bytes * 4; /* 4 Cache-Lines = 256 Bytes */
        if (r.optimale_blockgroesse < 256) r.optimale_blockgroesse = 256;

        /* 256er-Netz (LUT+INV = 512 Bytes) passt in L1-Cache? */
        uint32_t netz_groesse_kb = 1; /* 512 Bytes ~ 0.5 KB, aufgerundet */
        r.cluster_im_cache = (netz_groesse_kb <= r.l1_cache_kb) ? 1 : 0;

        /* Effizienz-Faktor: Basierend auf Cache/RAM-Verhaeltnis und CPU-Kernen */
        float cache_score = 0.0f;
        if (r.l1_cache_kb >= 32) cache_score += 30.0f;
        if (r.l2_cache_kb >= 256) cache_score += 20.0f;
        float cpu_score = 0.0f;
        if (r.cpu_kerne >= 8) cpu_score = 30.0f;
        else if (r.cpu_kerne >= 4) cpu_score = 25.0f;
        else if (r.cpu_kerne >= 2) cpu_score = 15.0f;
        else cpu_score = 10.0f;
        float ram_score = 0.0f;
        if (r.ram_total_kb >= 16 * 1024 * 1024) ram_score = 20.0f;      /* 16 GB+ */
        else if (r.ram_total_kb >= 8 * 1024 * 1024) ram_score = 15.0f;  /* 8 GB+ */
        else if (r.ram_total_kb >= 4 * 1024 * 1024) ram_score = 10.0f;  /* 4 GB+ */
        else ram_score = 5.0f;

        r.effizienz_faktor = (cache_score + cpu_score + ram_score) / 100.0f;
    }

    /* §250: Thermische Ueberwachung & Taktische Deckelung
     * Pruefe /sys/class/thermal fuer Temperatur-Sensoren.
     * Berechne max Operationen pro Burst basierend auf Hardware. */
    {
        r.thermisch_ok = 1; /* Default: OK */

        /* Versuche Temperatur aus Linux-Thermal-Zone zu lesen */
        FILE *tf = fopen("/sys/class/thermal/thermal_zone0/temp", "r");
        if (tf) {
            long temp_milli = 0;
            if (fscanf(tf, "%ld", &temp_milli) == 1) {
                /* temp_milli ist in Milli-Grad Celsius */
                if (temp_milli > 85000) { /* > 85°C => Warnung */
                    r.thermisch_ok = 0;
                }
            }
            fclose(tf);
        }

        /* Max Operationen pro Burst: CPU-Kerne * Cache-freundliche Groesse */
        r.max_ops_pro_burst = r.cpu_kerne * 256 * 16; /* 256er-Netz * 16 Iterationen */

        /* Hardware-Score: Gesamtbewertung 0-100 */
        r.hw_score = r.effizienz_faktor * 100.0f;
        if (r.cluster_im_cache) r.hw_score += 5.0f;
        if (r.thermisch_ok) r.hw_score += 5.0f;
        if (r.hw_score > 100.0f) r.hw_score = 100.0f;
    }

    /* Siegel */
    uint8_t sbuf[64];
    memset(sbuf, 0, sizeof(sbuf));
    memcpy(sbuf, &r.cpu_kerne, 4);
    memcpy(sbuf + 4, &r.ram_total_kb, 8);
    memcpy(sbuf + 12, &r.cache_line_bytes, 4);
    memcpy(sbuf + 16, &r.l1_cache_kb, 4);
    memcpy(sbuf + 20, &r.l2_cache_kb, 4);
    memcpy(sbuf + 24, &r.page_size, 4);
    memcpy(sbuf + 28, &r.optimale_blockgroesse, 4);
    sbuf[32] = r.cluster_im_cache;
    memcpy(sbuf + 33, &r.effizienz_faktor, sizeof(float));
    sbuf[37] = r.thermisch_ok;
    memcpy(sbuf + 38, &r.max_ops_pro_burst, 4);
    memcpy(sbuf + 42, &r.hw_score, sizeof(float));
    r.siegel = uhcs_crc32(sbuf, sizeof(sbuf));

    return r;
}

