    printf("║    Optimale Blockgroesse:    %u Bytes\n", hw->optimale_blockgroesse);
    printf("║    256er-Netz im Cache:      %s\n", hw->cluster_im_cache ? "JA (L1-resident)" : "NEIN");
    printf("║    Effizienz-Faktor:         %.2f (0.00-1.00)\n", hw->effizienz_faktor);
    printf("║  §250 Thermische Ueberwachung & Taktische Deckelung                    ║\n");
