    PluginSchnittstelle p;
    memset(&p, 0, sizeof(p));
    /* §344: Registrierung */
    if (name) {
        strncpy(p.name, name, sizeof(p.name) - 1);
        p.name[sizeof(p.name) - 1] = '\0';
    }
    p.version = version;
    p.geladen = 1;
