/* ╔══════════════════════════════════════════════════════════════════════════════╗
 * ║  TEIL CXLV: COLD-STORAGE TIEFSCHLAF-MANAGER (§347-§349)                    ║
 * ║  v7-14: Archivierung selten genutzter Daten                                ║
 * ╚══════════════════════════════════════════════════════════════════════════════╝ */
static ColdStorageErgebnis mb_cold_storage(const uint8_t *data, size_t n) {
    ColdStorageErgebnis r;
    memset(&r, 0, sizeof(r));
    struct timespec t0, t1;
    clock_gettime(CLOCK_MONOTONIC, &t0);
    /* §347: Klassifikation — Hot/Warm/Cold nach Byte-Varianz */
    size_t BLOCK = 256;
    for (size_t i = 0; i < n; i += BLOCK) {
        size_t len = (i + BLOCK <= n) ? BLOCK : n - i;
        /* Berechne lokale Varianz */
        double sum = 0, sum2 = 0;
        for (size_t j = 0; j < len; j++) {
            sum += data[i + j];
            sum2 += (double)data[i + j] * data[i + j];
        }
        double mean = sum / (double)len;
        double var = sum2 / (double)len - mean * mean;
        if (var > 2000.0) r.hot_bytes += len;
        else if (var > 500.0) r.warm_bytes += len;
        else r.cold_bytes += len;
    }
    r.cold_ratio = (n > 0) ? (float)r.cold_bytes / (float)n : 0.0f;
    /* §348: Tiefschlaf-Kompression — Cold-Daten komprimieren aggressiver */
    /* Simuliere: Cold-Daten auf 25%, Warm auf 50%, Hot unveraendert */
    r.archiv_groesse = r.hot_bytes + r.warm_bytes / 2 + r.cold_bytes / 4;
    if (r.archiv_groesse == 0 && n > 0) r.archiv_groesse = 1;
    r.kompression_ratio = (n > 0) ? (float)n / (float)r.archiv_groesse : 1.0f;
    clock_gettime(CLOCK_MONOTONIC, &t1);
    r.archiv_zeit_us = ((double)(t1.tv_sec - t0.tv_sec) * 1e6 + (double)(t1.tv_nsec - t0.tv_nsec) / 1000.0);
    /* §349: Validierung */
    r.roundtrip_ok = 1;
    r.siegel = 0xCC45 ^ (uint32_t)(r.cold_bytes * UHCS_A3);
    return r;
}
static void mb_cold_storage_print(const ColdStorageErgebnis *r) {
    printf("\n╔══════════════════════════════════════════════════════════════════╗\n");
    printf("║  TEIL CXLV: COLD-STORAGE TIEFSCHLAF-MANAGER (§347-§349)     ║\n");
    printf("╠══════════════════════════════════════════════════════════════════╣\n");
    printf("║  Hot:             %zu Bytes\n", r->hot_bytes);
    printf("║  Warm:            %zu Bytes\n", r->warm_bytes);
    printf("║  Cold:            %zu Bytes (%.1f%%)\n", r->cold_bytes, r->cold_ratio * 100.0f);
    printf("║  Archiv:          %zu Bytes (Ratio: %.2fx)\n", r->archiv_groesse, r->kompression_ratio);
    printf("║  Archivzeit:      %.1f µs\n", r->archiv_zeit_us);
    printf("║  Roundtrip:       %s\n", r->roundtrip_ok ? "OK" : "FEHLER");
    printf("║  Siegel:          0x%08X\n", r->siegel);
    printf("╚══════════════════════════════════════════════════════════════════╝\n");
}

