    printf("║  Vollstaendigkeit: %.0f%%\n", r->vollstaendigkeit * 100.0f);
    printf("║  Hardware-reif:   %s\n", r->hardware_reif ? "JA ✓" : "NEIN");
    printf("║  Zertifikat:      0x%08X\n", r->zertifikat_hash);
