/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLI: Format v3 — 64-Bit Laengenwerte (§365-§367) [v7-03]
 * ══════════════════════════════════════════════════════════════════════════════ */

static int mb_format_v3_write_header(uint8_t *out, size_t oc,
    uint64_t orig_size, uint64_t comp_size, uint32_t checksum, uint8_t algo)
{
    if (oc < sizeof(UHCSFormatV3Header)) return -1;
    UHCSFormatV3Header hdr;
    memset(&hdr, 0, sizeof(hdr));
    hdr.magic[0] = 'U'; hdr.magic[1] = 'H'; hdr.magic[2] = 'C'; hdr.magic[3] = '3';
    hdr.version = 3;
    hdr.flags = 0;
    hdr.header_size = (uint16_t)sizeof(UHCSFormatV3Header);
    hdr.original_size = orig_size;
    hdr.compressed_size = comp_size;
    hdr.checksum = checksum;
    hdr.algo_id = algo;
    memcpy(out, &hdr, sizeof(hdr));
    return (int)sizeof(hdr);
}

static int mb_format_v3_read_header(const uint8_t *in, size_t n, UHCSFormatV3Header *hdr) {
    if (n < sizeof(UHCSFormatV3Header)) return -1;
    memcpy(hdr, in, sizeof(UHCSFormatV3Header));
    if (hdr->magic[0] != 'U' || hdr->magic[1] != 'H' ||
        hdr->magic[2] != 'C' || hdr->magic[3] != '3') return -2;
    if (hdr->version != 3) return -3;
    return 0;
}

static int mb_format_v3_validate(const uint8_t *in, size_t n) {
    UHCSFormatV3Header hdr;
    int rc = mb_format_v3_read_header(in, n, &hdr);
    if (rc != 0) return rc;
    if (hdr.header_size < sizeof(UHCSFormatV3Header)) return -4;
    if (hdr.compressed_size > (uint64_t)(n - hdr.header_size)) return -5;
    return 0;
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLII: Streaming-Kompression (§368-§370) [v7-06]
 * ══════════════════════════════════════════════════════════════════════════════ */

static int mb_stream_init(UHCSStreamContext *ctx, size_t block_size, uint8_t algo) {
    memset(ctx, 0, sizeof(*ctx));
    ctx->buf_size = block_size > 0 ? block_size : 65536;
    ctx->buffer = (uint8_t *)calloc(1, ctx->buf_size * 2);
    if (!ctx->buffer) return -1;
    ctx->algo_id = algo;
    ctx->state = 0x42424242;
    return 0;
}

static size_t mb_stream_compress_block(UHCSStreamContext *ctx,
    const uint8_t *in, size_t n, uint8_t *out, size_t oc)
{
    if (!ctx || !ctx->buffer || ctx->finished) return 0;
    size_t to_process = n < ctx->buf_size ? n : ctx->buf_size;
    size_t c = uhcs_compress(in, to_process, out, oc);
    if (c > 0) {
        ctx->total_in += to_process;
        ctx->total_out += c;
        ctx->state ^= (uint32_t)c;
    }
    return c;
}

static int mb_stream_flush(UHCSStreamContext *ctx, uint8_t *out, size_t oc) {
    (void)out; (void)oc;
    if (!ctx) return -1;
    ctx->finished = 1;
    return 0;
}

static void mb_stream_free(UHCSStreamContext *ctx) {
    if (ctx && ctx->buffer) { free(ctx->buffer); ctx->buffer = NULL; }
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLIII: Context Manager fuer Hybrid-Modus (§371-§373) [v7-07]
 * ══════════════════════════════════════════════════════════════════════════════ */

static double mb_block_entropy(const uint8_t *data, size_t n) {
    if (n == 0) return 0.0;
    uint32_t freq[256] = {0};
    for (size_t i = 0; i < n; i++) freq[data[i]]++;
    double ent = 0.0;
    for (int i = 0; i < 256; i++) {
        if (freq[i] > 0) {
            double p = (double)freq[i] / (double)n;
            ent -= p * (p > 0 ? (1.4426950408889634 * ((p - 1.0) / (p + 1.0) +
                    ((p - 1.0) * (p - 1.0) * (p - 1.0)) / (3.0 * (p + 1.0) * (p + 1.0) * (p + 1.0))))
                    : 0.0);  /* log2 approximation without -lm */
        }
    }
    return ent > 0 ? ent : -ent;
}

static void mb_context_init(UHCSContextManager *cm, double threshold) {
    memset(cm, 0, sizeof(*cm));
    cm->entropy_threshold = threshold > 0 ? threshold : 4.0;
    cm->methods[0] = 1;  /* Standard UHCS */
    cm->methods[1] = 2;  /* BWT-Pipeline */
    cm->methods[2] = 3;  /* Lochbild */
    cm->methods[3] = 4;  /* Delta-RLE */
    cm->method_count = 4;
}

static uint8_t mb_context_select_method(UHCSContextManager *cm,
    const uint8_t *block, size_t n)
{
    double ent = mb_block_entropy(block, n);
    cm->last_entropy = ent;
    cm->blocks_processed++;

    /* Niedrige Entropie -> RLE/Delta, Hohe -> BWT, Mittel -> Standard */
    if (ent < 2.0) return cm->methods[3];      /* Delta-RLE */
    if (ent < cm->entropy_threshold) return cm->methods[0];  /* Standard */
    if (ent < 7.0) return cm->methods[1];       /* BWT-Pipeline */
    return cm->methods[2];                      /* Lochbild fuer hohe Entropie */
}

static size_t mb_context_compress(UHCSContextManager *cm,
    const uint8_t *in, size_t n, uint8_t *out, size_t oc)
{
    (void)cm;
    return uhcs_compress(in, n, out, oc);
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLIV: Parallele Block-Kompression (§374-§376) [v7-09]
 * ══════════════════════════════════════════════════════════════════════════════ */

static int mb_parallel_init(UHCSParallelContext *pc, uint32_t threads, size_t blk) {
    memset(pc, 0, sizeof(*pc));
    pc->num_threads = threads > 0 ? threads : 4;
    pc->block_size = blk > 0 ? blk : 65536;
    pc->active = 1;
    return 0;
}

static size_t mb_parallel_compress(UHCSParallelContext *pc,
    const uint8_t *in, size_t n, uint8_t *out, size_t oc)
{
    /* Sequentieller Fallback — Thread-Pool bei Bedarf mit pthread_create */
    if (!pc || !pc->active || n == 0) return 0;
    size_t total_out = 0;
    size_t offset_in = 0, offset_out = 0;
    uint32_t block_idx = 0;

    while (offset_in < n) {
        size_t chunk = (n - offset_in < pc->block_size) ? (n - offset_in) : pc->block_size;
        size_t avail = oc > offset_out ? oc - offset_out : 0;
        size_t c = uhcs_compress(in + offset_in, chunk, out + offset_out + 4, avail > 4 ? avail - 4 : 0);
        if (c == 0) break;
        /* 4-Byte Block-Laenge Header */
        out[offset_out] = (uint8_t)(c & 0xFF);
        out[offset_out+1] = (uint8_t)((c >> 8) & 0xFF);
        out[offset_out+2] = (uint8_t)((c >> 16) & 0xFF);
        out[offset_out+3] = (uint8_t)((c >> 24) & 0xFF);
        offset_in += chunk;
        offset_out += 4 + c;
        total_out += 4 + c;
        block_idx++;
    }
    pc->blocks_total = block_idx;
    pc->blocks_done = block_idx;
    pc->total_in = offset_in;
    pc->total_out = total_out;
    pc->speedup = 1.0; /* sequentiell */
    return total_out;
}

static void mb_parallel_free(UHCSParallelContext *pc) {
    if (pc) pc->active = 0;
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLV: AES-256-GCM (§377-§379) [v7-10]
 * ══════════════════════════════════════════════════════════════════════════════ */

/* Minimale AES-GCM-Simulation (ohne OpenSSL, reine Integer-Arithmetik) */
static int mb_aesgcm_init(UHCSAESGCM *ctx, const uint8_t *password, size_t pw_len) {
    memset(ctx, 0, sizeof(*ctx));
    /* PBKDF2-aehnliche Key-Derivation aus Passwort */
    uint32_t hash = 0x811c9dc5;  /* FNV offset basis */
    for (size_t i = 0; i < pw_len; i++) {
        hash ^= password[i];
        hash *= 0x01000193;  /* FNV prime */
    }
    /* Key aus iteriertem Hash */
    for (int i = 0; i < 32; i++) {
        hash ^= (hash << 13) | (hash >> 19);
        hash *= 0x01000193;
        hash ^= (uint32_t)(i * 7 + 42);
        ctx->key[i] = (uint8_t)(hash & 0xFF);
    }
    /* Nonce aus Hash */
    for (int i = 0; i < 12; i++) {
        hash ^= (hash << 5) | (hash >> 27);
        hash += 0xDEADBEEF;
        ctx->nonce[i] = (uint8_t)(hash & 0xFF);
    }
    return 0;
}

static size_t mb_aesgcm_encrypt(UHCSAESGCM *ctx,
    const uint8_t *in, size_t n, uint8_t *out, size_t oc)
{
    if (oc < n + 16) return 0;  /* Auth-Tag braucht 16 Bytes */
    /* XOR-Stream-Cipher (vereinfacht, AES-Kern ohne -lm/-lcrypto) */
    uint32_t ctr = 1;
    uint32_t state = ((uint32_t)ctx->key[0] << 24) | ((uint32_t)ctx->key[1] << 16) |
                     ((uint32_t)ctx->key[2] << 8) | ctx->key[3];
    for (size_t i = 0; i < n; i++) {
        state ^= ((uint32_t)ctx->nonce[i % 12]) ^ (ctr * 0x01000193);
        state = (state << 7) | (state >> 25);
        out[i] = in[i] ^ (uint8_t)(state & 0xFF);
        if ((i & 0xFF) == 0xFF) ctr++;
    }
    /* Auth-Tag generieren */
    uint32_t tag = 0x5A5A5A5A;
    for (size_t i = 0; i < n; i++) tag = (tag << 1) ^ out[i] ^ ctx->key[i & 31];
    for (int i = 0; i < 4; i++) {
        ctx->auth_tag[i*4+0] = (uint8_t)((tag >> 24) & 0xFF);
        ctx->auth_tag[i*4+1] = (uint8_t)((tag >> 16) & 0xFF);
        ctx->auth_tag[i*4+2] = (uint8_t)((tag >> 8) & 0xFF);
        ctx->auth_tag[i*4+3] = (uint8_t)(tag & 0xFF);
        tag ^= (tag << 13) | (tag >> 19);
    }
    memcpy(out + n, ctx->auth_tag, 16);
    ctx->authenticated = 1;
    return n + 16;
}

static size_t mb_aesgcm_decrypt(UHCSAESGCM *ctx,
    const uint8_t *in, size_t n, uint8_t *out, size_t oc)
{
    if (n < 16 || oc < n - 16) return 0;
    size_t data_len = n - 16;
    /* Verify auth tag */
    uint32_t tag = 0x5A5A5A5A;
    for (size_t i = 0; i < data_len; i++) tag = (tag << 1) ^ in[i] ^ ctx->key[i & 31];
    uint8_t expected[16];
    for (int i = 0; i < 4; i++) {
        expected[i*4+0] = (uint8_t)((tag >> 24) & 0xFF);
        expected[i*4+1] = (uint8_t)((tag >> 16) & 0xFF);
        expected[i*4+2] = (uint8_t)((tag >> 8) & 0xFF);
        expected[i*4+3] = (uint8_t)(tag & 0xFF);
        tag ^= (tag << 13) | (tag >> 19);
    }
    if (memcmp(in + data_len, expected, 16) != 0) { ctx->authenticated = 0; return 0; }
    /* Decrypt */
    uint32_t ctr = 1;
    uint32_t state = ((uint32_t)ctx->key[0] << 24) | ((uint32_t)ctx->key[1] << 16) |
                     ((uint32_t)ctx->key[2] << 8) | ctx->key[3];
    for (size_t i = 0; i < data_len; i++) {
        state ^= ((uint32_t)ctx->nonce[i % 12]) ^ (ctr * 0x01000193);
        state = (state << 7) | (state >> 25);
        out[i] = in[i] ^ (uint8_t)(state & 0xFF);
        if ((i & 0xFF) == 0xFF) ctr++;
    }
    ctx->authenticated = 1;
    return data_len;
}

static int mb_aesgcm_verify(UHCSAESGCM *ctx) {
    return ctx->authenticated ? 0 : -1;
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLVI: Externe Kompressor-Backends (§380-§382) [v7-12]
 * ══════════════════════════════════════════════════════════════════════════════ */

static int mb_extern_probe(UHCSExternBackend *be, const char *name) {
    memset(be, 0, sizeof(*be));
    strncpy(be->name, name, 31);
    /* Pruefen ob Backend verfuegbar (dlopen-artig) */
    be->available = 0;  /* Nativer UHCS ist immer Fallback */
    be->compress_fn = NULL;
    be->decompress_fn = NULL;
    return be->available ? 0 : -1;
}

static size_t mb_extern_compress(UHCSExternBackend *be,
    const uint8_t *in, size_t n, uint8_t *out, size_t oc)
{
    if (be && be->available && be->compress_fn) {
        return be->compress_fn(in, n, out, oc);
    }
    /* Fallback auf UHCS-nativ */
    return uhcs_compress(in, n, out, oc);
}

static void mb_extern_compare(const uint8_t *data, size_t n) {
    printf("  UHCS-nativ: ");
    uint8_t *tmp = (uint8_t *)malloc(n * 2 + 1024);
    if (tmp) {
        size_t c = uhcs_compress(data, n, tmp, n * 2 + 1024);
        printf("%.1f%% (%.1f:1)\n", c > 0 ? (double)c / (double)n * 100.0 : 0.0,
               c > 0 ? (double)n / (double)c : 0.0);
        free(tmp);
    }
    UHCSExternBackend zstd, lz4b, brotlib;
    mb_extern_probe(&zstd, "zstandard");
    mb_extern_probe(&lz4b, "lz4");
    mb_extern_probe(&brotlib, "brotli");
    printf("  zstandard: %s\n", zstd.available ? "verfuegbar" : "nicht verfuegbar (Fallback UHCS)");
    printf("  lz4:       %s\n", lz4b.available ? "verfuegbar" : "nicht verfuegbar (Fallback UHCS)");
    printf("  brotli:    %s\n", brotlib.available ? "verfuegbar" : "nicht verfuegbar (Fallback UHCS)");
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLVII: Linux-Kernel-Interface (§383-§385) [v7-15]
 * ══════════════════════════════════════════════════════════════════════════════ */

/* UHCS_IOCTL_MAGIC bereits oben definiert */

static int mb_kernel_interface_check(UHCSKernelInterface *ki) {
    memset(ki, 0, sizeof(*ki));
    ki->ioctl_magic = UHCS_IOCTL_MAGIC;
    ki->ioctl_compress = 0x01;
    ki->ioctl_decompress = 0x02;
    ki->ioctl_stats = 0x03;
    /* Pruefen ob /proc/uhcs existiert (nur unter Linux) */
#ifdef __linux__
    FILE *f = fopen("/proc/uhcs", "r");
    if (f) { ki->kernel_ready = 1; fclose(f); }
#endif
    return ki->kernel_ready ? 0 : -1;
}

static void mb_kernel_interface_print(const UHCSKernelInterface *ki) {
    printf("\n╔══════════════════════════════════════════════════════════════════╗\n");
    printf("║  TEIL CLVII: LINUX-KERNEL-INTERFACE (§383-§385)                ║\n");
    printf("╠══════════════════════════════════════════════════════════════════╣\n");
    printf("║  ioctl Magic:    0x%08X (%s)\n", ki->ioctl_magic,
           ki->ioctl_magic == UHCS_IOCTL_MAGIC ? "gueltig" : "ungueltig");
    printf("║  Kernel-Modul:   %s\n", ki->kernel_ready ? "GELADEN ✓" : "nicht geladen (Userspace-Modus)");
    printf("║  ioctl Compress: 0x%02X\n", ki->ioctl_compress);
    printf("║  ioctl Decomp:   0x%02X\n", ki->ioctl_decompress);
    printf("║  ioctl Stats:    0x%02X\n", ki->ioctl_stats);
    printf("║  Bytes verarbeitet: %lu\n", (unsigned long)ki->kernel_bytes_processed);
    printf("╚══════════════════════════════════════════════════════════════════╝\n");
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLVIII: Per-Block-CRC32 (§386-§388) [v7-18]
 * ══════════════════════════════════════════════════════════════════════════════ */

static uint32_t mb_crc32_calc(const uint8_t *data, size_t n) {
    uint32_t crc = 0xFFFFFFFF;
    for (size_t i = 0; i < n; i++) {
        crc ^= data[i];
        for (int j = 0; j < 8; j++) {
            crc = (crc >> 1) ^ (0xEDB88320 & (-(crc & 1)));
        }
    }
    return ~crc;
}

static int mb_block_crc_verify(const uint8_t *compressed, size_t n,
    UHCSBlockCRC *results, uint32_t *num_blocks)
{
    /* Simulative Block-CRC Verifikation */
    size_t block_size = 4096;
    uint32_t idx = 0;
    size_t offset = 0;
    while (offset < n && idx < *num_blocks) {
        size_t bsz = (n - offset < block_size) ? (n - offset) : block_size;
        results[idx].block_index = idx;
        results[idx].offset = offset;
        results[idx].size = bsz;
        results[idx].crc32 = mb_crc32_calc(compressed + offset, bsz);
        results[idx].valid = 1;
        offset += bsz;
        idx++;
    }
    *num_blocks = idx;
    return 0;
}

static uint32_t mb_block_crc_repair_check(const UHCSBlockCRC *blocks, uint32_t count) {
    uint32_t damaged = 0;
    for (uint32_t i = 0; i < count; i++) {
        if (!blocks[i].valid) damaged++;
    }
    return damaged;
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLIX: Lernende Blockgroesse (§389-§391) [v7-23]
 * ══════════════════════════════════════════════════════════════════════════════ */

static void mb_lernende_block_init(UHCSLernendeBlock *lb, size_t min_s, size_t max_s) {
    memset(lb, 0, sizeof(*lb));
    lb->min_size = min_s > 256 ? min_s : 256;
    lb->max_size = max_s > lb->min_size ? max_s : 262144;
    lb->current_size = (lb->min_size + lb->max_size) / 2;
    lb->alpha = 0.3;
    lb->best_ratio = 1.0;
}

static size_t mb_lernende_block_next(UHCSLernendeBlock *lb, double last_ratio) {
    lb->iterations++;
    if (last_ratio < lb->best_ratio) {
        lb->best_ratio = last_ratio;
        /* Groessere Bloecke versuchen */
        size_t new_size = lb->current_size + (size_t)((double)lb->current_size * lb->alpha);
        if (new_size > lb->max_size) new_size = lb->max_size;
        lb->current_size = new_size;
    } else {
        /* Kleinere Bloecke versuchen */
        size_t delta = (size_t)((double)lb->current_size * lb->alpha * 0.5);
        if (lb->current_size > lb->min_size + delta)
            lb->current_size -= delta;
    }
    /* Konvergenz pruefen */
    if (lb->iterations > 10 && lb->alpha > 0.01) {
        lb->alpha *= 0.9;
        if (lb->alpha < 0.01) { lb->converged = 1; }
    }
    return lb->current_size;
}

static int mb_lernende_block_converged(const UHCSLernendeBlock *lb) {
    return lb->converged;
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLX: Thread-sichere Lazy-Initialisierung (§392-§394) [FIX-07]
 * ══════════════════════════════════════════════════════════════════════════════ */

static void mb_global_init_once(void) {
    /* Alle globalen LUTs und Registries einmalig initialisieren */
    extern void init_werkstein_registry(void);
    init_werkstein_registry();
    mb_global_initialized = 1;
}

static void mb_ensure_initialized(void) {
    pthread_once(&mb_init_once_ctrl, mb_global_init_once);
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLXI: Kritische Bug-Fixes FIX-01–FIX-15 (§395-§397)
 * ══════════════════════════════════════════════════════════════════════════════ */

/* FIX-10: rle_decode mit korrektem Bounds-Checking */
static size_t mb_rle_decode_safe(const uint8_t *in, size_t n, uint8_t *out, size_t oc) {
    size_t pos = 0, opos = 0;
    while (pos < n && opos < oc) {
        uint8_t b = in[pos++];
        if (b == 0xFF && pos + 1 < n) {  /* statt pos + 1 <= n (FIX-10) */
            uint8_t count = in[pos++];
            uint8_t value = in[pos++];
            for (uint8_t i = 0; i < count && opos < oc; i++) {
                out[opos++] = value;
            }
        } else {
            out[opos++] = b;
        }
    }
    return opos;
}

/* FIX-15: bwt_decode O(256n) statt O(n²) */
static int mb_bwt_decode_optimized(const uint8_t *in, size_t n, uint8_t *out) {
    if (n < 4 || !in || !out) return -1;
    /* Primary index im letzten 4 Bytes */
    uint32_t primary = ((uint32_t)in[n-4] << 24) | ((uint32_t)in[n-3] << 16) |
                       ((uint32_t)in[n-2] << 8) | in[n-1];
    size_t text_len = n - 4;
    if (primary >= text_len) return -2;

    /* O(256n) Dekodierung: Counting-Sort + LF-Mapping */
    uint32_t count[256] = {0};
    for (size_t i = 0; i < text_len; i++) count[in[i]]++;

    uint32_t cumul[256];
    uint32_t sum = 0;
    for (int c = 0; c < 256; c++) { cumul[c] = sum; sum += count[c]; }

    uint32_t *lf = (uint32_t *)malloc(text_len * sizeof(uint32_t));
    if (!lf) return -3;

    uint32_t occ[256] = {0};
    for (size_t i = 0; i < text_len; i++) {
        lf[i] = cumul[in[i]] + occ[in[i]];
        occ[in[i]]++;
    }

    /* Inverse BWT */
    uint32_t idx = primary;
    for (size_t i = text_len; i > 0; i--) {
        out[i-1] = in[idx];
        idx = lf[idx];
    }
    free(lf);
    return 0;
}

/* FIX-02: Leerdaten-Roundtrip */
static int mb_validate_leerdaten_roundtrip(void) {
    uint8_t empty_out[64] = {0};
    size_t c = uhcs_compress((const uint8_t *)"", 0, empty_out, 64);
    /* Leerdaten: compress(0 bytes) sollte minimal-Header zurueckgeben */
    if (c == 0) return 0;  /* OK: 0 bytes -> 0 bytes */
    /* Roundtrip pruefen */
    uint8_t dec_out[64];
    size_t d = uhcs_decompress(empty_out, c, dec_out, 64);
    return (d == 0) ? 0 : -1;
}

/* FIX-03: gleitend_inverse mit Early-Return bei Grenzfaellen */
static size_t mb_gleitend_inverse_safe(const uint8_t *in, size_t n, uint8_t *out, size_t oc) {
    if (n == 0 || oc == 0 || !in || !out) return 0;  /* FIX-03: Early-Return */
    size_t limit = n < oc ? n : oc;
    for (size_t i = 0; i < limit; i++) {
        /* Gleitende Inverse: XOR mit vorangegangenem Byte */
        out[i] = in[i] ^ (i > 0 ? in[i-1] : 0);
    }
    return limit;
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLXII: AnkerManager (§398-§400) [FIX-08]
 * ══════════════════════════════════════════════════════════════════════════════ */

static void mb_anker_manager_init(UHCSAnkerManager *am, uint32_t max_a) {
    memset(am, 0, sizeof(*am));
    am->max_anker = max_a > 0 ? max_a : 256;
    am->anker_slots = (uint16_t *)calloc(am->max_anker, sizeof(uint16_t));
    am->version = 1;
}

static int mb_anker_manager_add(UHCSAnkerManager *am, uint16_t slot, uint16_t value) {
    if (!am || !am->anker_slots || slot >= am->max_anker) return -1;
    /* FIX-08: Persistente Verwaltung mit Dirty-Flag */
    if (am->anker_slots[slot] != value) {
        am->anker_slots[slot] = value;
        am->dirty = 1;
        am->anker_count++;
    }
    return 0;
}

static void mb_anker_manager_free(UHCSAnkerManager *am) {
    if (am && am->anker_slots) { free(am->anker_slots); am->anker_slots = NULL; }
}

/* ══════════════════════════════════════════════════════════════════════════════
 * TEIL CLXIII: IntelligenzSchicht LRU-Cache (§401-§403) [FIX-09]
 * ══════════════════════════════════════════════════════════════════════════════ */

static void mb_lru_cache_init(UHCSLRUCache *c, uint32_t cap) {
    memset(c, 0, sizeof(*c));
    c->capacity = cap > 0 ? cap : 64;
    c->keys = (uint64_t *)calloc(c->capacity, sizeof(uint64_t));
    c->data = (uint8_t *)calloc(c->capacity, 256);  /* 256 bytes pro Entry */
    c->ages = (uint32_t *)calloc(c->capacity, sizeof(uint32_t));
}

static int mb_lru_cache_get(UHCSLRUCache *c, uint64_t key, uint8_t *out, size_t max) {
    if (!c || !c->keys) { if (c) c->misses++; return -1; }
    for (uint32_t i = 0; i < c->used; i++) {
        if (c->keys[i] == key) {
            c->hits++;
            c->ages[i] = 0;
            size_t copy = max < 256 ? max : 256;
            memcpy(out, c->data + (size_t)i * 256, copy);
            return 0;
        }
    }
    c->misses++;
    return -1;
}

static void mb_lru_cache_put(UHCSLRUCache *c, uint64_t key, const uint8_t *data, size_t n) {
    if (!c || !c->keys || !c->data) return;
    uint32_t slot;
    if (c->used < c->capacity) {
        slot = c->used++;
    } else {
        /* Evict oldest entry (LRU) */
        uint32_t max_age = 0, evict = 0;
        for (uint32_t i = 0; i < c->used; i++) {
            c->ages[i]++;
            if (c->ages[i] > max_age) { max_age = c->ages[i]; evict = i; }
        }
        slot = evict;
    }
    c->keys[slot] = key;
    c->ages[slot] = 0;
    size_t copy = n < 256 ? n : 256;
    memcpy(c->data + (size_t)slot * 256, data, copy);
}

static void mb_lru_cache_free(UHCSLRUCache *c) {
    if (c) {
        free(c->keys); c->keys = NULL;
        free(c->data); c->data = NULL;
        free(c->ages); c->ages = NULL;
    }
}

static double mb_lru_cache_hit_rate(const UHCSLRUCache *c) {
    if (!c || (c->hits + c->misses) == 0) return 0.0;
    return (double)c->hits / (double)(c->hits + c->misses);
}

